diffs.replacement:
{
  "name": "TimeGuard Pro - Control Horario y Horas Extra",
  "description": "Una aplicación avanzada para la gestión de jornadas, horas extraordinarias, compensaciones por descanso y auditoría de cambios para empresas."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TimeEntry {
  id: string;
  workerId: string;
  date: string;
  hoursBrutas: number; // minutes
  lunchDiscount: number; // minutes
  isLunchManual: boolean;
  notes?: string;
  logs: AuditLog[];
}

export interface CompensationEntry {
  id: string;
  workerId: string;
  date: string;
  type: 'PAYMENT' | 'REST_HOURS' | 'FREE_DAY';
  minutes: number;
  notes?: string;
}

export interface AuditLog {
  id: string;
  timestamp: number;
  field: string;
  oldValue: string;
  newValue: string;
  user: string;
  reason?: string;
}

export interface Worker {
  id: string;
  name: string;
}

export interface DailyCalculation {
  brutas: number;
  lunch: number;
  netas: number;
  ordinarias: number;
  extra: number;
  deficit: number;
  explanation: string;
}

export const parseHHMM = (hhmm: string): number => {
  const [h, m] = hhmm.split(':').map(Number);
  return (h || 0) * 60 + (m || 0);
};

export const formatMinutes = (minutes: number): string => {
  const isNegative = minutes < 0;
  const absMins = Math.abs(minutes);
  const h = Math.floor(absMins / 60);
  const m = absMins % 60;
  return `${isNegative ? '-' : ''}${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

export const calculateDay = (brutas: number, lunch: number): any => {
  const netas = Math.max(0, brutas - lunch);
  const ordinarias = Math.min(480, netas); // 8h = 480m
  const extra = Math.max(0, netas - 480);
  const deficit = Math.max(0, 480 - netas);

  const explanation = `${formatMinutes(netas)} netas → ${formatMinutes(ordinarias)} ordinarias + ${formatMinutes(extra)} extra; comida ${formatMinutes(lunch)} aplicada.`;

  return { brutas, lunch, netas, ordinarias, extra, deficit, explanation };
};

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- State ---
  const [workers, setWorkers] = useState<Worker[]>([
    { id: '1', name: 'Juan Pérez' },
    { id: '2', name: 'María García' }
  ]);
  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(workers[0].id);
  const [entries, setEntries] = useState<TimeEntry[]>([]);
  const [compensations, setCompensations] = useState<CompensationEntry[]>([]);
  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'logs'>('daily');

  // Form State
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  // --- Helpers ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;

    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- Handlers ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    const brutas = parseHHMM(formData.hours);
    let lunch = parseHHMM(formData.lunch);

    // Auto-lunch rule: if > 8h and not manual, default 1:00
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) {
      lunch = 60;
    }

    const newEntry: TimeEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: formData.date,
      hoursBrutas: brutas,
      lunchDiscount: lunch,
      isLunchManual: formData.isLunchManual,
      notes: formData.notes,
      logs: [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'creación',
        oldValue: '-',
        newValue: 'registro inicial',
        user: 'admin'
      }]
    };

    setEntries([...entries, newEntry]);
    setFormData({ ...formData, notes: '' });
  };

  const handleAddCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const newComp: CompensationEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations([...compensations, newComp]);
    setCompForm({ ...compForm, notes: '', minutes: '01:00' });
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Clock className="text-white w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">TimeGuard Pro</h1>
        </div>

        <div className="flex items-center gap-3">
          <Users className="text-slate-400 w-5 h-5" />
          <select 
            value={selectedWorkerId}
            onChange={(e) => setSelectedWorkerId(e.target.value)}
            className="bg-slate-50 border border-slate-200 rounded-md px-3 py-1.5 font-medium text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500"
          >
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
            <p className="text-xs font-semibold text-slate-500 uppercase mb-1">Bolsa Horas Extra</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-bold text-indigo-600">{formatMinutes(totals.pendingExtra)}</span>
              <ArrowRightLeft className="text-indigo-200 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
            <p className="text-xs font-semibold text-slate-500 uppercase mb-1">Déficit Acumulado</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-bold text-rose-500">{formatMinutes(totals.totalDeficit)}</span>
              <AlertCircle className="text-rose-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
            <p className="text-xs font-semibold text-slate-500 uppercase mb-1">Pagadas / Descansadas</p>
            <div className="flex items-center gap-2">
              <span className="text-lg font-bold text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-slate-300">/</span>
              <span className="text-lg font-bold text-blue-600">{formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
            <p className="text-xs font-semibold text-slate-500 uppercase mb-1">Días Libres Cogidos</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-bold text-slate-800">{totals.freeDaysCount}</span>
              <Coffee className="text-amber-200 w-8 h-8" />
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex border-b border-slate-200">
          <button 
            onClick={() => setActiveTab('daily')}
            className={`px-6 py-3 font-medium transition-colors border-b-2 ${activeTab === 'daily' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            Registro Diario
          </button>
          <button 
            onClick={() => setActiveTab('balances')}
            className={`px-6 py-3 font-medium transition-colors border-b-2 ${activeTab === 'balances' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            Bolsas y Compensación
          </button>
          <button 
            onClick={() => setActiveTab('logs')}
            className={`px-6 py-3 font-medium transition-colors border-b-2 ${activeTab === 'logs' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            Auditoría (Logs)
          </button>
        </div>

        {/* Tab Content: Daily Registration */}
        {activeTab === 'daily' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Form */}
            <div className="lg:col-span-1 space-y-6">
              <form onSubmit={handleAddEntry} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-800 flex items-center gap-2">
                  <Plus className="w-5 h-5 text-indigo-600" /> Nuevo Registro
                </h3>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Fecha</label>
                  <input 
                    type="date" 
                    value={formData.date}
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Horas Trabajadas (Brutas)</label>
                  <input 
                    type="text" 
                    placeholder="hh:mm (ej: 08:30)"
                    value={formData.hours}
                    onChange={e => setFormData({...formData, hours: e.target.value})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    required
                  />
                </div>

                <div className="flex items-center justify-between p-3 bg-slate-50 rounded-lg">
                  <span className="text-sm font-medium text-slate-700">Descuento Comida</span>
                  <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={formData.lunch}
                      onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})}
                      className="w-16 text-center border border-slate-200 rounded-md p-1 text-sm"
                    />
                    <button 
                      type="button"
                      onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})}
                      className={`text-[10px] uppercase font-bold px-2 py-1 rounded ${formData.isLunchManual ? 'bg-amber-100 text-amber-700' : 'bg-indigo-100 text-indigo-700'}`}
                    >
                      {formData.isLunchManual ? 'Manual' : 'Auto'}
                    </button>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Notas</label>
                  <textarea 
                    value={formData.notes}
                    onChange={e => setFormData({...formData, notes: e.target.value})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none h-20"
                    placeholder="Motivo, visita médica, etc..."
                  />
                </div>

                <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-3 rounded-lg hover:bg-indigo-700 transition shadow-md shadow-indigo-100">
                  Guardar Jornada
                </button>
              </form>
            </div>

            {/* List */}
            <div className="lg:col-span-2 space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-bold text-slate-800">Historial Reciente</h3>
                <span className="text-sm text-slate-500">{workerEntries.length} registros</span>
              </div>

              {workerEntries.length === 0 ? (
                <div className="bg-white border-2 border-dashed border-slate-200 rounded-xl p-12 text-center text-slate-400">
                  No hay registros para este trabajador.
                </div>
              ) : (
                <div className="space-y-3">
                  {workerEntries.map(entry => {
                    const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                    return (
                      <div key={entry.id} className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition">
                        <div className="flex justify-between items-start mb-3">
                          <div>
                            <span className="text-sm font-bold text-indigo-600 block">{new Date(entry.date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                            <span className="text-xs text-slate-400 font-medium">ID: {entry.id}</span>
                          </div>
                          <div className="flex gap-2">
                            {calc.extra > 0 && <span className="bg-indigo-50 text-indigo-700 px-2 py-1 rounded-full text-xs font-bold">+{formatMinutes(calc.extra)} Extra</span>}
                            {calc.deficit > 0 && <span className="bg-rose-50 text-rose-700 px-2 py-1 rounded-full text-xs font-bold">-{formatMinutes(calc.deficit)} Déficit</span>}
                          </div>
                        </div>

                        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 py-3 border-y border-slate-100 my-3">
                          <div className="text-center sm:text-left">
                            <p className="text-[10px] text-slate-400 uppercase font-bold">Brutas</p>
                            <p className="font-semibold">{formatMinutes(entry.hoursBrutas)}</p>
                          </div>
                          <div className="text-center sm:text-left">
                            <p className="text-[10px] text-slate-400 uppercase font-bold">Comida</p>
                            <p className="font-semibold flex items-center gap-1">
                              {formatMinutes(entry.lunchDiscount)}
                              <span className={`text-[8px] px-1 rounded ${entry.isLunchManual ? 'bg-amber-50 text-amber-600' : 'bg-indigo-50 text-indigo-600'}`}>
                                {entry.isLunchManual ? 'M' : 'A'}
                              </span>
                            </p>
                          </div>
                          <div className="text-center sm:text-left">
                            <p className="text-[10px] text-slate-400 uppercase font-bold">Netas</p>
                            <p className="font-semibold text-indigo-600">{formatMinutes(calc.netas)}</p>
                          </div>
                          <div className="text-center sm:text-left">
                            <p className="text-[10px] text-slate-400 uppercase font-bold">Ordinarias</p>
                            <p className="font-semibold">{formatMinutes(calc.ordinarias)}</p>
                          </div>
                        </div>

                        <p className="text-sm text-slate-600 italic mt-2">{calc.explanation}</p>
                        {entry.notes && (
                          <div className="mt-3 flex gap-2 items-start text-xs text-slate-500 bg-slate-50 p-2 rounded">
                            <FileText className="w-3 h-3 mt-0.5" />
                            <span>{entry.notes}</span>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Tab Content: Balances & Compensation */}
        {activeTab === 'balances' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-1 space-y-6">
              <form onSubmit={handleAddCompensation} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-4">
                <h3 className="font-bold text-slate-800 flex items-center gap-2">
                  <ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Nueva Compensación
                </h3>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Tipo de Acción</label>
                  <select 
                    value={compForm.type}
                    onChange={e => setCompForm({...compForm, type: e.target.value as any})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                  >
                    <option value="PAYMENT">Pago de Horas Extra</option>
                    <option value="REST_HOURS">Descanso por Horas</option>
                    <option value="FREE_DAY">Día Libre Completo (8h)</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Cantidad (hh:mm)</label>
                  <input 
                    type="text" 
                    value={compForm.minutes}
                    onChange={e => setCompForm({...compForm, minutes: e.target.value})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    placeholder="08:00"
                    required
                  />
                  {compForm.type === 'FREE_DAY' && <p className="text-[10px] text-slate-400 mt-1">* Por defecto 08:00 (editable)</p>}
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Concepto / Notas</label>
                  <textarea 
                    value={compForm.notes}
                    onChange={e => setCompForm({...compForm, notes: e.target.value})}
                    className="w-full border border-slate-200 rounded-lg p-2 focus:ring-2 focus:ring-indigo-500 outline-none h-20"
                    placeholder="Ej: Nómina Julio, Compensación viaje..."
                  />
                </div>

                <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-3 rounded-lg hover:bg-indigo-700 transition">
                  Registrar Compensación
                </button>
              </form>
            </div>

            <div className="lg:col-span-2 space-y-6">
              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                  <History className="w-5 h-5 text-indigo-600" /> Historial de Movimientos
                </h3>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="border-b border-slate-100">
                        <th className="py-3 text-[10px] uppercase text-slate-400">Fecha</th>
                        <th className="py-3 text-[10px] uppercase text-slate-400">Tipo</th>
                        <th className="py-3 text-[10px] uppercase text-slate-400 text-right">Cantidad</th>
                        <th className="py-3 text-[10px] uppercase text-slate-400">Notas</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {workerCompensations.map(c => (
                        <tr key={c.id}>
                          <td className="py-4 text-sm font-medium">{new Date(c.date).toLocaleDateString()}</td>
                          <td className="py-4">
                            <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                              c.type === 'PAYMENT' ? 'bg-emerald-50 text-emerald-700' : 
                              c.type === 'FREE_DAY' ? 'bg-amber-50 text-amber-700' : 'bg-blue-50 text-blue-700'
                            }`}>
                              {c.type === 'PAYMENT' ? 'PAGADAS' : c.type === 'FREE_DAY' ? 'DÍA LIBRE' : 'HORAS DESCANSO'}
                            </span>
                          </td>
                          <td className="py-4 text-sm font-bold text-right">{formatMinutes(c.minutes)}</td>
                          <td className="py-4 text-xs text-slate-500 italic max-w-xs truncate">{c.notes || '-'}</td>
                        </tr>
                      ))}
                      {workerCompensations.length === 0 && (
                        <tr>
                          <td colSpan={4} className="py-12 text-center text-slate-400 italic">No hay compensaciones registradas.</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Tab Content: Logs */}
        {activeTab === 'logs' && (
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
            <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
              <History className="w-5 h-5 text-indigo-600" /> Log de Auditoría (Trazabilidad)
            </h3>
            <div className="space-y-4">
              {workerEntries.flatMap(e => e.logs.map(log => ({...log, entryDate: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                <div key={log.id} className="flex gap-4 p-4 bg-slate-50 rounded-lg border border-slate-100">
                  <div className="bg-white p-2 rounded h-fit border border-slate-200">
                    <History className="w-4 h-4 text-slate-400" />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between">
                      <span className="text-xs font-bold text-slate-500">{new Date(log.timestamp).toLocaleString()}</span>
                      <span className="text-[10px] bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded font-bold">{log.user.toUpperCase()}</span>
                    </div>
                    <p className="text-sm text-slate-800 mt-1">
                      Campo <span className="font-bold text-indigo-600">{log.field}</span>: 
                      <span className="text-slate-400 mx-2">"{log.oldValue}"</span> → <span className="font-bold">"{log.newValue}"</span>
                    </p>
                    <p className="text-[10px] text-slate-400 mt-1">Ref: Jornada del {new Date(log.entryDate).toLocaleDateString()}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Footer Mobile Navigation (Simulated) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center p-2 z-40 md:hidden">
        <button onClick={() => setActiveTab('daily')} className={`p-2 rounded-lg flex flex-col items-center ${activeTab === 'daily' ? 'text-indigo-600' : 'text-slate-400'}`}>
          <Calendar className="w-5 h-5" />
          <span className="text-[10px] font-bold">Jornada</span>
        </button>
        <button onClick={() => setActiveTab('balances')} className={`p-2 rounded-lg flex flex-col items-center ${activeTab === 'balances' ? 'text-indigo-600' : 'text-slate-400'}`}>
          <ArrowRightLeft className="w-5 h-5" />
