          <span className="text-[10px] font-bold">Log</span>
        </button>
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- Persistencia ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Juan Pérez' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(workers[0]?.id || '');
  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('tw_workers', JSON.stringify(workers)), [workers]);
  useEffect(() => localStorage.setItem('tw_entries', JSON.stringify(entries)), [entries]);
  useEffect(() => localStorage.setItem('tw_compensations', JSON.stringify(compensations)), [compensations]);

  // Form States
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- Helpers ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- Handlers ---
  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name: newWorkerName.trim()
    };
    setWorkers([...workers, newWorker]);
    setNewWorkerName('');
    if (!selectedWorkerId) setSelectedWorkerId(newWorker.id);
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm('¿Estás seguro? Se borrarán todos sus registros y compensaciones.')) {
      setWorkers(workers.filter(w => w.id !== id));
      setEntries(entries.filter(e => e.workerId !== id));
      setCompensations(compensations.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0]?.id || '');
    }
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return alert('Selecciona un trabajador primero');
    const brutas = parseHHMM(formData.hours);
    let lunch = parseHHMM(formData.lunch);

    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    const newEntry: TimeEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: formData.date,
      hoursBrutas: brutas,
      lunchDiscount: lunch,
      isLunchManual: formData.isLunchManual,
      notes: formData.notes,
      logs: [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'creación',
        oldValue: '-',
        newValue: 'registro inicial',
        user: 'admin'
      }]
    };

    setEntries([...entries, newEntry]);
    setFormData({ ...formData, notes: '' });
  };

  const handleAddCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;
    const newComp: CompensationEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations([...compensations, newComp]);
    setCompForm({ ...compForm, notes: '', minutes: '01:00' });
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg shadow-sm shadow-indigo-200">
            <Clock className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Control de Presencia</p>
          </div>
        </div>

        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select 
            value={selectedWorkerId}
            onChange={(e) => setSelectedWorkerId(e.target.value)}
            className="bg-transparent border-none rounded-md px-2 py-1 font-semibold text-slate-700 outline-none min-w-[150px]"
          >
            {workers.length === 0 && <option value="">Sin trabajadores</option>}
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-indigo-600 tracking-tight">{formatMinutes(totals.pendingExtra)}</span>
              <ArrowRightLeft className="text-indigo-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Déficit Acumulado</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-rose-500 tracking-tight">{formatMinutes(totals.totalDeficit)}</span>
              <AlertCircle className="text-rose-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Compensadas (Pago/Desc)</p>
            <div className="flex items-center gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-slate-300">/</span>
              <span className="text-xl font-black text-blue-600">{formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Días Libres</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-slate-800 tracking-tight">{totals.freeDaysCount}</span>
              <Coffee className="text-amber-100 w-8 h-8" />
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex overflow-x-auto border-b border-slate-200 no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensación', icon: ArrowRightLeft },
            { id: 'workers', label: 'Trabajadores', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 whitespace-nowrap ${
                activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/30' : 'border-transparent text-slate-500 hover:text-slate-800'
              }`}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Views */}
        {!selectedWorkerId && activeTab !== 'workers' ? (
          <div className="bg-amber-50 border border-amber-200 p-8 rounded-2xl text-center">
            <Users className="w-12 h-12 text-amber-400 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-amber-900">No hay trabajador seleccionado</h2>
            <p className="text-amber-700 mt-2">Ve a la pestaña de Trabajadores para añadir uno.</p>
            <button onClick={() => setActiveTab('workers')} className="mt-4 bg-amber-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-amber-700 transition">Añadir ahora</button>
          </div>
        ) : (
          <>
            {activeTab === 'daily' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddEntry} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2">
                      <Plus className="w-5 h-5 text-indigo-600" /> Registrar Horas
                    </h3>
                    <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Fecha</label>
                          <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                        </div>
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Horas (hh:mm)</label>
                          <input type="text" placeholder="08:00" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                        </div>
                      </div>
                      <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase">Comida</p>
                          <input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-20 bg-transparent border-none p-0 text-lg font-bold text-slate-700 outline-none" />
                        </div>
                        <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${formData.isLunchManual ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-indigo-100 text-indigo-700 border border-indigo-200'}`}>
                          {formData.isLunchManual ? 'Manual' : 'Automático'}
                        </button>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Notas internas</label>
                        <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-medium focus:ring-2 focus:ring-indigo-500 outline-none h-24" placeholder="Incidencias del día..." />
                      </div>
                      <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center justify-center gap-2">
                        <Plus className="w-5 h-5" /> Guardar Jornada
                      </button>
                    </div>
                  </form>
                </div>

                <div className="lg:col-span-2 space-y-4">
                  {workerEntries.length === 0 ? (
                    <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl p-20 text-center">
                      <Calendar className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                      <p className="text-slate-400 font-bold">No hay jornadas registradas para {selectedWorker?.name}</p>
                    </div>
                  ) : (
                    workerEntries.map(entry => {
                      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                      return (
                        <div key={entry.id} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:border-indigo-200 transition-all">
                          <div className="flex justify-between items-start mb-4">
                            <div>
                              <span className="text-sm font-black text-slate-800">{new Date(entry.date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
