                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Brutas</p><p className="font-bold text-slate-700">{formatMinutes(entry.hoursBrutas)}</p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Comida</p><p className="font-bold text-slate-700 flex items-center gap-1.5">{formatMinutes(entry.lunchDiscount)} <span className="text-[8px] bg-slate-100 px-1 rounded uppercase">{entry.isLunchManual ? 'M' : 'A'}</span></p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Netas</p><p className="font-bold text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Ordinarias</p><p className="font-bold text-slate-700">{formatMinutes(calc.ordinarias)}</p></div>
                          </div>
                          <p className="text-xs font-medium text-slate-500 bg-slate-50 p-2.5 rounded-lg border border-slate-100">{calc.explanation}</p>
