                          {selectedWorkerId === w.id ? 'Seleccionado' : 'Seleccionar'}
                        </button>
                        <button onClick={() => handleDeleteWorker(w.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition">
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'logs' && (
              <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 overflow-hidden">
                <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2"><History className="w-5 h-5 text-indigo-600" /> Trazabilidad de Cambios</h3>
                <div className="space-y-4">
                  {workerEntries.flatMap(e => e.logs.map(log => ({...log, entryDate: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                    <div key={log.id} className="flex gap-4 p-4 bg-slate-50 rounded-xl border border-slate-100">
                      <div className="bg-white p-2.5 rounded-lg h-fit border border-slate-200 shadow-sm"><History className="w-4 h-4 text-slate-400" /></div>
                      <div className="flex-1">
                        <div className="flex justify-between items-center mb-1">
                          <span className="text-[11px] font-black text-slate-400">{new Date(log.timestamp).toLocaleString()}</span>
                          <span className="text-[9px] bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full font-black uppercase tracking-tighter">{log.user}</span>
                        </div>
                        <p className="text-sm text-slate-700 font-medium">
                          Modificado campo <span className="font-black text-indigo-600 uppercase text-[10px]">{log.field}</span>: 
                          <span className="text-slate-400 line-through mx-2 text-xs">"{log.oldValue}"</span> 
                          <ArrowRightLeft className="w-3 h-3 inline text-slate-300 mx-1" />
                          <span className="font-black text-slate-900">"{log.newValue}"</span>
                        </p>
                        <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-wide">Ref. Jornada: {new Date(log.entryDate).toLocaleDateString()}</p>
                      </div>
                    </div>
                  ))}
                  {workerEntries.length === 0 && <p className="text-center py-10 text-slate-400 italic">No hay registros de auditoría aún.</p>}
                </div>
              </div>
            )}
          </>
        )}
      </main>

      {/* Mobile Nav */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-lg border-t border-slate-200 flex justify-around items-center p-3 z-40 md:hidden">
        {[
          { id: 'daily', label: 'Jornada', icon: Calendar },
          { id: 'balances', label: 'Saldos', icon: ArrowRightLeft },
          { id: 'workers', label: 'Equipo', icon: Users },
          { id: 'logs', label: 'Logs', icon: History }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`p-2 rounded-xl flex flex-col items-center transition-all ${activeTab === item.id ? 'text-indigo-600 scale-110' : 'text-slate-400 hover:text-slate-600'}`}>
            <item.icon className="w-5 h-5" />
            <span className="text-[9px] font-black uppercase mt-1 tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- Persistencia ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Juan Pérez' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(workers[0]?.id || '');
  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('tw_workers', JSON.stringify(workers)), [workers]);
  useEffect(() => localStorage.setItem('tw_entries', JSON.stringify(entries)), [entries]);
  useEffect(() => localStorage.setItem('tw_compensations', JSON.stringify(compensations)), [compensations]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- Helpers ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- Handlers ---
  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name: newWorkerName.trim()
    };
    setWorkers([...workers, newWorker]);
    setNewWorkerName('');
    if (!selectedWorkerId) setSelectedWorkerId(newWorker.id);
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm('¿Estás seguro? Se borrarán todos sus registros y compensaciones.')) {
      setWorkers(workers.filter(w => w.id !== id));
      setEntries(entries.filter(e => e.workerId !== id));
      setCompensations(compensations.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0]?.id || '');
    }
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return alert('Selecciona un trabajador primero');

    let brutas = 0;
    if (entryMode === 'direct') {
      brutas = parseHHMM(formData.hours);
    } else {
      const start = parseHHMM(formData.startTime);
      const end = parseHHMM(formData.endTime);
      brutas = end >= start ? end - start : (1440 - start) + end; // Handle overnight
    }

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    const newEntry: TimeEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: formData.date,
      hoursBrutas: brutas,
      lunchDiscount: lunch,
      isLunchManual: formData.isLunchManual,
      notes: formData.notes,
      logs: [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'creación',
        oldValue: '-',
        newValue: `registro inicial (${entryMode === 'clock' ? formData.startTime + ' - ' + formData.endTime : formData.hours})`,
        user: 'admin'
      }]
    };

    setEntries([...entries, newEntry]);
    setFormData({ ...formData, notes: '' });
  };

  const handleAddCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;
    const newComp: CompensationEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations([...compensations, newComp]);
    setCompForm({ ...compForm, notes: '', minutes: '01:00' });
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg shadow-sm shadow-indigo-200">
            <Clock className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Control de Presencia</p>
          </div>
        </div>

        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select 
            value={selectedWorkerId}
            onChange={(e) => setSelectedWorkerId(e.target.value)}
            className="bg-transparent border-none rounded-md px-2 py-1 font-semibold text-slate-700 outline-none min-w-[150px]"
          >
            {workers.length === 0 && <option value="">Sin trabajadores</option>}
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-indigo-600 tracking-tight">{formatMinutes(totals.pendingExtra)}</span>
              <ArrowRightLeft className="text-indigo-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Déficit Acumulado</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-rose-500 tracking-tight">{formatMinutes(totals.totalDeficit)}</span>
              <AlertCircle className="text-rose-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Compensadas (Pago/Desc)</p>
            <div className="flex items-center gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-slate-300">/</span>
              <span className="text-xl font-black text-blue-600">{formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Días Libres</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-slate-800 tracking-tight">{totals.freeDaysCount}</span>
              <Coffee className="text-amber-100 w-8 h-8" />
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex overflow-x-auto border-b border-slate-200 no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensación', icon: ArrowRightLeft },
            { id: 'workers', label: 'Trabajadores', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 whitespace-nowrap ${
                activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/30' : 'border-transparent text-slate-500 hover:text-slate-800'
              }`}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Views */}
        {!selectedWorkerId && activeTab !== 'workers' ? (
          <div className="bg-amber-50 border border-amber-200 p-8 rounded-2xl text-center">
            <Users className="w-12 h-12 text-amber-400 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-amber-900">No hay trabajador seleccionado</h2>
            <p className="text-amber-700 mt-2">Ve a la pestaña de Trabajadores para añadir uno.</p>
            <button onClick={() => setActiveTab('workers')} className="mt-4 bg-amber-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-amber-700 transition">Añadir ahora</button>
          </div>
        ) : (
          <>
            {activeTab === 'daily' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddEntry} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2">
                      <Plus className="w-5 h-5 text-indigo-600" /> Registrar Horas
                    </h3>

                    {/* Entry Mode Switch */}
                    <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
                      <button 
                        type="button" 
                        onClick={() => setEntryMode('clock')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-xs font-bold transition ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
                      >
                        <Timer className="w-3.5 h-3.5" /> Inicio / Fin
                      </button>
                      <button 
                        type="button" 
                        onClick={() => setEntryMode('direct')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-xs font-bold transition ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
                      >
                        <FileText className="w-3.5 h-3.5" /> Total Horas
                      </button>
                    </div>

                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Fecha</label>
                        <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                      </div>

                      {entryMode === 'clock' ? (
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Entrada</label>
                            <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Salida</label>
                            <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                          </div>
                        </div>
                      ) : (
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Horas Totales (hh:mm)</label>
                          <input type="text" placeholder="08:00" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                        </div>
                      )}

                      <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase">Comida</p>
                          <input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-20 bg-transparent border-none p-0 text-lg font-bold text-slate-700 outline-none" />
                        </div>
                        <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${formData.isLunchManual ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-indigo-100 text-indigo-700 border border-indigo-200'}`}>
                          {formData.isLunchManual ? 'Manual' : 'Automático'}
                        </button>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Notas internas</label>
                        <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-medium focus:ring-2 focus:ring-indigo-500 outline-none h-24" placeholder="Incidencias del día..." />
                      </div>
                      <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center justify-center gap-2">
                        <Plus className="w-5 h-5" /> Guardar Jornada
                      </button>
                    </div>
                  </form>
                </div>

                <div className="lg:col-span-2 space-y-4">
                  {workerEntries.length === 0 ? (
                    <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl p-20 text-center">
                      <Calendar className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                      <p className="text-slate-400 font-bold">No hay jornadas registradas para {selectedWorker?.name}</p>
                    </div>
                  ) : (
                    workerEntries.map(entry => {
                      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                      return (
                        <div key={entry.id} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:border-indigo-200 transition-all">
                          <div className="flex justify-between items-start mb-4">
                            <div>
                              <span className="text-sm font-black text-slate-800">{new Date(entry.date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                              <p className="text-[10px] font-bold text-slate-400 uppercase mt-0.5">ID REG: {entry.id}</p>
                            </div>
                            <div className="flex gap-2">
                              {calc.extra > 0 && <span className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-[11px] font-black border border-indigo-100">+{formatMinutes(calc.extra)} EXTRA</span>}
                              {calc.deficit > 0 && <span className="bg-rose-50 text-rose-700 px-3 py-1 rounded-full text-[11px] font-black border border-rose-100">-{formatMinutes(calc.deficit)} DÉFICIT</span>}
                            </div>
                          </div>
                          <div className="grid grid-cols-2 sm:grid-cols-4 gap-6 py-4 border-y border-slate-50 mb-4">
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Brutas</p><p className="font-bold text-slate-700">{formatMinutes(entry.hoursBrutas)}</p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Comida</p><p className="font-bold text-slate-700 flex items-center gap-1.5">{formatMinutes(entry.lunchDiscount)} <span className="text-[8px] bg-slate-100 px-1 rounded uppercase">{entry.isLunchManual ? 'M' : 'A'}</span></p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Netas</p><p className="font-bold text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Ordinarias</p><p className="font-bold text-slate-700">{formatMinutes(calc.ordinarias)}</p></div>
                          </div>
                          <p className="text-xs font-medium text-slate-500 bg-slate-50 p-2.5 rounded-lg border border-slate-100">{calc.explanation}</p>
                          {entry.notes && <div className="mt-3 text-xs text-slate-400 italic flex gap-2"><FileText className="w-3.5 h-3.5" /> {entry.notes}</div>}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>
            )}

            {activeTab === 'balances' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddCompensation} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Gestionar Saldo</h3>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Tipo de compensación</label>
                      <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-slate-200 border rounded-xl p-3 font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none">
                        <option value="PAYMENT">Pago de Horas Extra</option>
                        <option value="REST_HOURS">Descanso (Horas sueltas)</option>
                        <option value="FREE_DAY">Día Libre Completo (8h)</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Cantidad (hh:mm)</label>
                      <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" required />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Concepto</label>
                      <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-medium focus:ring-2 focus:ring-indigo-500 outline-none h-24" placeholder="Referencia de nómina, festivo compensado..." />
                    </div>
                    <button type="submit" className="w-full bg-slate-800 text-white font-bold py-4 rounded-xl hover:bg-black transition-all shadow-lg shadow-slate-200">Registrar Cambio</button>
                  </form>
                </div>
                <div className="lg:col-span-2">
                  <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                      <h3 className="font-bold text-slate-800">Historial de Compensaciones</h3>
                    </div>
                    <div className="overflow-x-auto">
                      <table className="w-full text-left">
                        <thead className="bg-slate-50">
                          <tr>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Fecha</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Acción</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Cantidad</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Notas</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                          {workerCompensations.map(c => (
                            <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                              <td className="px-6 py-4 text-sm font-bold text-slate-700">{new Date(c.date).toLocaleDateString()}</td>
                              <td className="px-6 py-4">
                                <span className={`px-2.5 py-1 rounded-full text-[10px] font-black border ${
                                  c.type === 'PAYMENT' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 
                                  c.type === 'FREE_DAY' ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-blue-50 text-blue-700 border-blue-100'
                                }`}>
                                  {c.type === 'PAYMENT' ? 'PAGADAS' : c.type === 'FREE_DAY' ? 'DÍA LIBRE' : 'DESCANSO'}
                                </span>
                              </td>
                              <td className="px-6 py-4 text-sm font-black text-right text-slate-800">{formatMinutes(c.minutes)}</td>
                              <td className="px-6 py-4 text-xs text-slate-400 italic max-w-xs truncate">{c.notes || '-'}</td>
                            </tr>
                          ))}
                          {workerCompensations.length === 0 && (
                            <tr><td colSpan={4} className="py-16 text-center text-slate-400 italic font-medium">No hay movimientos registrados.</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'workers' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddWorker} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Empleado</h3>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Nombre Completo</label>
                      <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-slate-200 border rounded-xl p-3 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Ej: Elena Martínez" required />
                    </div>
                    <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-100">Crear Trabajador</button>
                  </form>
                </div>
                <div className="lg:col-span-2 space-y-3">
                  <h3 className="font-bold text-slate-800 mb-2">Lista de Trabajadores</h3>
                  {workers.map(w => (
                    <div key={w.id} className={`flex items-center justify-between p-4 bg-white rounded-2xl border transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 ring-1 ring-indigo-600' : 'border-slate-200 shadow-sm'}`}>
                      <div className="flex items-center gap-4">
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-lg ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                          {w.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-black text-slate-800">{w.name}</p>
                          <p className="text-[10px] font-bold text-slate-400 uppercase">UID: {w.id}</p>
                        </div>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => setSelectedWorkerId(w.id)} className={`px-4 py-2 rounded-xl text-xs font-bold transition ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                          {selectedWorkerId === w.id ? 'Seleccionado' : 'Seleccionar'}
                        </button>
                        <button onClick={() => handleDeleteWorker(w.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition">
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'logs' && (
              <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 overflow-hidden">
                <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2"><History className="w-5 h-5 text-indigo-600" /> Trazabilidad de Cambios</h3>
                <div className="space-y-4">
                  {workerEntries.flatMap(e => e.logs.map(log => ({...log, entryDate: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                    <div key={log.id} className="flex gap-4 p-4 bg-slate-50 rounded-xl border border-slate-100">
                      <div className="bg-white p-2.5 rounded-lg h-fit border border-slate-200 shadow-sm"><History className="w-4 h-4 text-slate-400" /></div>
                      <div className="flex-1">
                        <div className="flex justify-between items-center mb-1">
                          <span className="text-[11px] font-black text-slate-400">{new Date(log.timestamp).toLocaleString()}</span>
                          <span className="text-[9px] bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full font-black uppercase tracking-tighter">{log.user}</span>
                        </div>
                        <p className="text-sm text-slate-700 font-medium">
                          Modificado campo <span className="font-black text-indigo-600 uppercase text-[10px]">{log.field}</span>: 
                          <span className="text-slate-400 line-through mx-2 text-xs">"{log.oldValue}"</span> 
                          <ArrowRightLeft className="w-3 h-3 inline text-slate-300 mx-1" />
                          <span className="font-black text-slate-900">"{log.newValue}"</span>
                        </p>
                        <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-wide">Ref. Jornada: {new Date(log.entryDate).toLocaleDateString()}</p>
                      </div>
                    </div>
                  ))}
                  {workerEntries.length === 0 && <p className="text-center py-10 text-slate-400 italic">No hay registros de auditoría aún.</p>}
                </div>
              </div>
            )}
          </>
        )}
      </main>

      {/* Mobile Nav */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-lg border-t border-slate-200 flex justify-around items-center p-3 z-40 md:hidden">
        {[
          { id: 'daily', label: 'Jornada', icon: Calendar },
          { id: 'balances', label: 'Saldos', icon: ArrowRightLeft },
          { id: 'workers', label: 'Equipo', icon: Users },
          { id: 'logs', label: 'Logs', icon: History }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`p-2 rounded-xl flex flex-col items-center transition-all ${activeTab === item.id ? 'text-indigo-600 scale-110' : 'text-slate-400 hover:text-slate-600'}`}>
            <item.icon className="w-5 h-5" />
            <span className="text-[9px] font-black uppercase mt-1 tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- Persistencia ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Juan Pérez' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(workers[0]?.id || '');
  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('tw_workers', JSON.stringify(workers)), [workers]);
  useEffect(() => localStorage.setItem('tw_entries', JSON.stringify(entries)), [entries]);
  useEffect(() => localStorage.setItem('tw_compensations', JSON.stringify(compensations)), [compensations]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null, // Para saber si editamos
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- Helpers ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- Handlers ---
  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name: newWorkerName.trim()
    };
    setWorkers([...workers, newWorker]);
    setNewWorkerName('');
    if (!selectedWorkerId) setSelectedWorkerId(newWorker.id);
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm('¿Estás seguro? Se borrarán todos sus registros y compensaciones.')) {
      setWorkers(workers.filter(w => w.id !== id));
      setEntries(entries.filter(e => e.workerId !== id));
      setCompensations(compensations.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0]?.id || '');
    }
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return alert('Selecciona un trabajador primero');

    let brutas = 0;
    if (entryMode === 'direct') {
      brutas = parseHHMM(formData.hours);
    } else {
      const start = parseHHMM(formData.startTime);
      const end = parseHHMM(formData.endTime);
      brutas = end >= start ? end - start : (1440 - start) + end; // Handle overnight
    }

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    const newEntry: TimeEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: formData.date,
      hoursBrutas: brutas,
      lunchDiscount: lunch,
      isLunchManual: formData.isLunchManual,
      notes: formData.notes,
      logs: [{
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'creación',
        oldValue: '-',
        newValue: `registro inicial (${entryMode === 'clock' ? formData.startTime + ' - ' + formData.endTime : formData.hours})`,
        user: 'admin'
      }]
    };

    setEntries([...entries, newEntry]);
    setFormData({ ...formData, notes: '' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;

    if (compForm.id) {
      // Editar existente
      setCompensations(compensations.map(c => 
        c.id === compForm.id 
          ? { ...c, type: compForm.type, minutes: parseHHMM(compForm.minutes), notes: compForm.notes }
          : c
      ));
    } else {
      // Crear nuevo
      const newComp: CompensationEntry = {
        id: Math.random().toString(36).substr(2, 9),
        workerId: selectedWorkerId,
        date: new Date().toISOString().split('T')[0],
        type: compForm.type,
        minutes: parseHHMM(compForm.minutes),
        notes: compForm.notes
      };
      setCompensations([...compensations, newComp]);
    }

    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

  const handleEditComp = (comp: CompensationEntry) => {
    setCompForm({
      id: comp.id,
      type: comp.type,
      minutes: formatMinutes(comp.minutes),
      notes: comp.notes || ''
    });
    // Scroll al formulario en móviles
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteComp = (id: string) => {
    if (confirm('¿Eliminar este registro de compensación? El saldo se actualizará.')) {
      setCompensations(compensations.filter(c => c.id !== id));
      if (compForm.id === id) setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
    }
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg shadow-sm shadow-indigo-200">
            <Clock className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Control de Presencia</p>
          </div>
        </div>

        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select 
            value={selectedWorkerId}
            onChange={(e) => {
              setSelectedWorkerId(e.target.value);
              setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
            }}
            className="bg-transparent border-none rounded-md px-2 py-1 font-semibold text-slate-700 outline-none min-w-[150px]"
          >
            {workers.length === 0 && <option value="">Sin trabajadores</option>}
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-indigo-600 tracking-tight">{formatMinutes(totals.pendingExtra)}</span>
              <ArrowRightLeft className="text-indigo-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Déficit Acumulado</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-rose-500 tracking-tight">{formatMinutes(totals.totalDeficit)}</span>
              <AlertCircle className="text-rose-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Compensadas (Pago/Desc)</p>
            <div className="flex items-center gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-slate-300">/</span>
              <span className="text-xl font-black text-blue-600">{formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Días Libres</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-slate-800 tracking-tight">{totals.freeDaysCount}</span>
              <Coffee className="text-amber-100 w-8 h-8" />
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex overflow-x-auto border-b border-slate-200 no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensación', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 whitespace-nowrap ${
                activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/30' : 'border-transparent text-slate-500 hover:text-slate-800'
              }`}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Views */}
        {!selectedWorkerId && activeTab !== 'workers' ? (
          <div className="bg-amber-50 border border-amber-200 p-8 rounded-2xl text-center">
            <Users className="w-12 h-12 text-amber-400 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-amber-900">No hay trabajador seleccionado</h2>
            <p className="text-amber-700 mt-2">Ve a la pestaña de Trabajadores para añadir uno.</p>
            <button onClick={() => setActiveTab('workers')} className="mt-4 bg-amber-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-amber-700 transition">Añadir ahora</button>
          </div>
        ) : (
          <>
            {activeTab === 'daily' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddEntry} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2">
                      <Plus className="w-5 h-5 text-indigo-600" /> Registrar Horas
                    </h3>

                    {/* Entry Mode Switch */}
                    <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
                      <button 
                        type="button" 
                        onClick={() => setEntryMode('clock')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-xs font-bold transition ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
                      >
                        <Timer className="w-3.5 h-3.5" /> Inicio / Fin
                      </button>
                      <button 
                        type="button" 
                        onClick={() => setEntryMode('direct')}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-xs font-bold transition ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
                      >
                        <FileText className="w-3.5 h-3.5" /> Total Horas
                      </button>
                    </div>

                    <div className="space-y-4">
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Fecha</label>
                        <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                      </div>

                      {entryMode === 'clock' ? (
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Entrada</label>
                            <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                          </div>
                          <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Salida</label>
                            <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                          </div>
                        </div>
                      ) : (
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Horas Totales (hh:mm)</label>
                          <input type="text" placeholder="08:00" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-slate-200 border rounded-xl p-2.5 font-medium focus:ring-2 focus:ring-indigo-500 outline-none" required />
                        </div>
                      )}

                      <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase">Comida</p>
                          <input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-20 bg-transparent border-none p-0 text-lg font-bold text-slate-700 outline-none" />
                        </div>
                        <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${formData.isLunchManual ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-indigo-100 text-indigo-700 border border-indigo-200'}`}>
                          {formData.isLunchManual ? 'Manual' : 'Automático'}
                        </button>
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Notas internas</label>
                        <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-medium focus:ring-2 focus:ring-indigo-500 outline-none h-24" placeholder="Incidencias del día..." />
                      </div>
                      <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center justify-center gap-2">
                        <Plus className="w-5 h-5" /> Guardar Jornada
                      </button>
                    </div>
                  </form>
                </div>

                <div className="lg:col-span-2 space-y-4">
                  {workerEntries.length === 0 ? (
                    <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl p-20 text-center">
                      <Calendar className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                      <p className="text-slate-400 font-bold">No hay jornadas registradas para {selectedWorker?.name}</p>
                    </div>
                  ) : (
                    workerEntries.map(entry => {
                      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                      return (
                        <div key={entry.id} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:border-indigo-200 transition-all">
                          <div className="flex justify-between items-start mb-4">
                            <div>
                              <span className="text-sm font-black text-slate-800">{new Date(entry.date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                              <p className="text-[10px] font-bold text-slate-400 uppercase mt-0.5">ID REG: {entry.id}</p>
                            </div>
                            <div className="flex gap-2">
                              {calc.extra > 0 && <span className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-[11px] font-black border border-indigo-100">+{formatMinutes(calc.extra)} EXTRA</span>}
                              {calc.deficit > 0 && <span className="bg-rose-50 text-rose-700 px-3 py-1 rounded-full text-[11px] font-black border border-rose-100">-{formatMinutes(calc.deficit)} DÉFICIT</span>}
                            </div>
                          </div>
                          <div className="grid grid-cols-2 sm:grid-cols-4 gap-6 py-4 border-y border-slate-50 mb-4">
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Brutas</p><p className="font-bold text-slate-700">{formatMinutes(entry.hoursBrutas)}</p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Comida</p><p className="font-bold text-slate-700 flex items-center gap-1.5">{formatMinutes(entry.lunchDiscount)} <span className="text-[8px] bg-slate-100 px-1 rounded uppercase">{entry.isLunchManual ? 'M' : 'A'}</span></p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Netas</p><p className="font-bold text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                            <div><p className="text-[9px] font-black text-slate-400 uppercase mb-1">Ordinarias</p><p className="font-bold text-slate-700">{formatMinutes(calc.ordinarias)}</p></div>
                          </div>
                          <p className="text-xs font-medium text-slate-500 bg-slate-50 p-2.5 rounded-lg border border-slate-100">{calc.explanation}</p>
                          {entry.notes && <div className="mt-3 text-xs text-slate-400 italic flex gap-2"><FileText className="w-3.5 h-3.5" /> {entry.notes}</div>}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>
            )}

            {activeTab === 'balances' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleSaveCompensation} className={`bg-white p-6 rounded-2xl border transition-all shadow-sm space-y-4 ${compForm.id ? 'border-amber-400 ring-2 ring-amber-100' : 'border-slate-200'}`}>
                    <div className="flex justify-between items-center mb-2">
                      <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        {compForm.id ? <Edit2 className="w-5 h-5 text-amber-500" /> : <ArrowRightLeft className="w-5 h-5 text-indigo-600" />}
                        {compForm.id ? 'Editar Registro' : 'Gestionar Saldo'}
                      </h3>
                      {compForm.id && (
                        <button type="button" onClick={() => setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' })} className="text-slate-400 hover:text-rose-500 p-1">
                          <X className="w-5 h-5" />
                        </button>
                      )}
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Tipo de compensación</label>
                      <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-slate-200 border rounded-xl p-3 font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none">
                        <option value="PAYMENT">Pago de Horas Extra</option>
                        <option value="REST_HOURS">Descanso (Horas sueltas)</option>
                        <option value="FREE_DAY">Día Libre Completo (8h)</option>
                      </select>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Cantidad (hh:mm)</label>
                      <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" required />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Concepto</label>
                      <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-medium focus:ring-2 focus:ring-indigo-500 outline-none h-24" placeholder="Referencia de nómina, festivo compensado..." />
                    </div>
                    <button type="submit" className={`w-full text-white font-bold py-4 rounded-xl transition-all shadow-lg ${compForm.id ? 'bg-amber-600 hover:bg-amber-700 shadow-amber-100' : 'bg-slate-800 hover:bg-black shadow-slate-200'}`}>
                      {compForm.id ? 'Actualizar Registro' : 'Registrar Cambio'}
                    </button>
                  </form>
                </div>
                <div className="lg:col-span-2">
                  <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                      <h3 className="font-bold text-slate-800">Historial de Compensaciones</h3>
                    </div>
                    <div className="overflow-x-auto">
                      <table className="w-full text-left">
                        <thead className="bg-slate-50">
                          <tr>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Fecha</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Acción</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Cantidad</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Acciones</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                          {workerCompensations.map(c => (
                            <tr key={c.id} className={`hover:bg-slate-50/50 transition-colors ${compForm.id === c.id ? 'bg-amber-50/50' : ''}`}>
                              <td className="px-6 py-4 text-sm font-bold text-slate-700">{new Date(c.date).toLocaleDateString()}</td>
                              <td className="px-6 py-4">
                                <span className={`px-2.5 py-1 rounded-full text-[10px] font-black border ${
                                  c.type === 'PAYMENT' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 
                                  c.type === 'FREE_DAY' ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-blue-50 text-blue-700 border-blue-100'
                                }`}>
                                  {c.type === 'PAYMENT' ? 'PAGADAS' : c.type === 'FREE_DAY' ? 'DÍA LIBRE' : 'DESCANSO'}
                                </span>
                                <p className="text-[10px] text-slate-400 italic mt-1 max-w-[150px] truncate">{c.notes}</p>
                              </td>
                              <td className="px-6 py-4 text-sm font-black text-right text-slate-800">{formatMinutes(c.minutes)}</td>
                              <td className="px-6 py-4 text-right">
                                <div className="flex justify-end gap-1">
                                  <button onClick={() => handleEditComp(c)} className="p-2 text-amber-500 hover:bg-amber-50 rounded-lg transition" title="Editar">
                                    <Edit2 className="w-4 h-4" />
                                  </button>
                                  <button onClick={() => handleDeleteComp(c.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg transition" title="Eliminar">
                                    <Trash2 className="w-4 h-4" />
                                  </button>
                                </div>
                              </td>
                            </tr>
                          ))}
                          {workerCompensations.length === 0 && (
                            <tr><td colSpan={4} className="py-16 text-center text-slate-400 italic font-medium">No hay movimientos registrados.</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'workers' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddWorker} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Empleado</h3>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1">Nombre Completo</label>
                      <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-slate-200 border rounded-xl p-3 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Ej: Elena Martínez" required />
                    </div>
                    <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-100">Crear Trabajador</button>
                  </form>
                </div>
                <div className="lg:col-span-2 space-y-3">
                  <h3 className="font-bold text-slate-800 mb-2">Lista de Trabajadores</h3>
                  {workers.map(w => (
                    <div key={w.id} className={`flex items-center justify-between p-4 bg-white rounded-2xl border transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 ring-1 ring-indigo-600' : 'border-slate-200 shadow-sm'}`}>
                      <div className="flex items-center gap-4">
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-lg ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                          {w.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-black text-slate-800">{w.name}</p>
                          <p className="text-[10px] font-bold text-slate-400 uppercase">UID: {w.id}</p>
                        </div>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => setSelectedWorkerId(w.id)} className={`px-4 py-2 rounded-xl text-xs font-bold transition ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                          {selectedWorkerId === w.id ? 'Seleccionado' : 'Seleccionar'}
                        </button>
                        <button onClick={() => handleDeleteWorker(w.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition">
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'logs' && (
              <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 overflow-hidden">
                <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2"><History className="w-5 h-5 text-indigo-600" /> Trazabilidad de Cambios</h3>
                <div className="space-y-4">
                  {workerEntries.flatMap(e => e.logs.map(log => ({...log, entryDate: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                    <div key={log.id} className="flex gap-4 p-4 bg-slate-50 rounded-xl border border-slate-100">
                      <div className="bg-white p-2.5 rounded-lg h-fit border border-slate-200 shadow-sm"><History className="w-4 h-4 text-slate-400" /></div>
                      <div className="flex-1">
                        <div className="flex justify-between items-center mb-1">
                          <span className="text-[11px] font-black text-slate-400">{new Date(log.timestamp).toLocaleString()}</span>
                          <span className="text-[9px] bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full font-black uppercase tracking-tighter">{log.user}</span>
                        </div>
                        <p className="text-sm text-slate-700 font-medium">
                          Modificado campo <span className="font-black text-indigo-600 uppercase text-[10px]">{log.field}</span>: 
                          <span className="text-slate-400 line-through mx-2 text-xs">"{log.oldValue}"</span> 
                          <ArrowRightLeft className="w-3 h-3 inline text-slate-300 mx-1" />
                          <span className="font-black text-slate-900">"{log.newValue}"</span>
                        </p>
                        <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase tracking-wide">Ref. Jornada: {new Date(log.entryDate).toLocaleDateString()}</p>
                      </div>
                    </div>
                  ))}
                  {workerEntries.length === 0 && <p className="text-center py-10 text-slate-400 italic">No hay registros de auditoría aún.</p>}
                </div>
              </div>
            )}
          </>
        )}
      </main>

      {/* Mobile Nav */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-lg border-t border-slate-200 flex justify-around items-center p-3 z-40 md:hidden">
        {[
          { id: 'daily', label: 'Jornada', icon: Calendar },
          { id: 'balances', label: 'Saldos', icon: ArrowRightLeft },
          { id: 'workers', label: 'Equipo', icon: Users },
          { id: 'logs', label: 'Logs', icon: History }
        ].map(item => (
          <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`p-2 rounded-xl flex flex-col items-center transition-all ${activeTab === item.id ? 'text-indigo-600 scale-110' : 'text-slate-400 hover:text-slate-600'}`}>
            <item.icon className="w-5 h-5" />
            <span className="text-[9px] font-black uppercase mt-1 tracking-tighter">{item.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X,
  Save
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- Persistencia ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Juan Pérez' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(workers[0]?.id || '');
  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('tw_workers', JSON.stringify(workers)), [workers]);
  useEffect(() => localStorage.setItem('tw_entries', JSON.stringify(entries)), [entries]);
  useEffect(() => localStorage.setItem('tw_compensations', JSON.stringify(compensations)), [compensations]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- Helpers ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- Handlers ---
  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name: newWorkerName.trim()
    };
    setWorkers([...workers, newWorker]);
    setNewWorkerName('');
    if (!selectedWorkerId) setSelectedWorkerId(newWorker.id);
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm('¿Estás seguro? Se borrarán todos sus registros y compensaciones.')) {
      setWorkers(workers.filter(w => w.id !== id));
      setEntries(entries.filter(e => e.workerId !== id));
      setCompensations(compensations.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0]?.id || '');
    }
  };

  const resetEntryForm = () => {
    setEditingEntryId(null);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      startTime: '08:00',
      endTime: '17:00',
      hours: '08:00',
      lunch: '01:00',
      isLunchManual: false,
      notes: ''
    });
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return alert('Selecciona un trabajador primero');

    let brutas = 0;
    if (entryMode === 'direct') {
      brutas = parseHHMM(formData.hours);
    } else {
      const start = parseHHMM(formData.startTime);
      const end = parseHHMM(formData.endTime);
      brutas = end >= start ? end - start : (1440 - start) + end;
    }

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      const oldEntry = entries.find(e => e.id === editingEntryId);
      if (!oldEntry) return;

      const newLog: AuditLog = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'edición jornada',
        oldValue: formatMinutes(oldEntry.hoursBrutas),
        newValue: formatMinutes(brutas),
        user: 'admin'
      };

      setEntries(entries.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, isLunchManual: formData.isLunchManual, notes: formData.notes, logs: [...ent.logs, newLog] }
          : ent
      ));
      resetEntryForm();
    } else {
      const newEntry: TimeEntry = {
        id: Math.random().toString(36).substr(2, 9),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: [{
          id: Math.random().toString(36).substr(2, 9),
          timestamp: Date.now(),
          field: 'creación',
          oldValue: '-',
          newValue: `registro inicial (${entryMode === 'clock' ? formData.startTime + ' - ' + formData.endTime : formData.hours})`,
          user: 'admin'
        }]
      };
      setEntries([...entries, newEntry]);
      setFormData({ ...formData, notes: '' });
    }
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', // Default if not saved
      endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteEntry = (id: string) => {
    if (confirm('¿Eliminar esta jornada? Los saldos se recalcularán.')) {
      setEntries(entries.filter(e => e.id !== id));
      if (editingEntryId === id) resetEntryForm();
    }
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;

    if (compForm.id) {
      setCompensations(compensations.map(c => 
        c.id === compForm.id 
          ? { ...c, type: compForm.type, minutes: parseHHMM(compForm.minutes), notes: compForm.notes }
          : c
      ));
    } else {
      const newComp: CompensationEntry = {
        id: Math.random().toString(36).substr(2, 9),
        workerId: selectedWorkerId,
        date: new Date().toISOString().split('T')[0],
        type: compForm.type,
        minutes: parseHHMM(compForm.minutes),
        notes: compForm.notes
      };
      setCompensations([...compensations, newComp]);
    }
    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

