                      </h3>
                      {editingEntryId && <button type="button" onClick={resetEntryForm} className="text-rose-500"><X /></button>}
                    </div>

                    <div className="flex p-1 bg-slate-100 rounded-xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition ${entryMode === 'clock' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Inicio/Fin</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition ${entryMode === 'direct' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Manual</button>
