                          <div className="flex gap-2">
                            {calc.extra > 0 && <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-[10px] font-black">+{formatMinutes(calc.extra)} EXTR</span>}
                            {calc.deficit > 0 && <span className="bg-rose-100 text-rose-700 px-3 py-1 rounded-full text-[10px] font-black">-{formatMinutes(calc.deficit)} DÉF</span>}
                            <div className="flex gap-1 ml-2">
                              <button onClick={() => handleEditEntry(entry)} className="p-1.5 text-amber-500 hover:bg-amber-50 rounded-lg"><Edit2 className="w-4 h-4" /></button>
