                          </div>
                        </div>
                        <div className="grid grid-cols-4 gap-4 py-3 border-y border-slate-100 mb-3 text-center">
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Bruta</p><p className="font-bold text-slate-700">{formatMinutes(entry.hoursBrutas)}</p></div>
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Comida</p><p className="font-bold text-slate-700">{formatMinutes(entry.lunchDiscount)}</p></div>
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Neta</p><p className="font-black text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Extra</p><p className="font-black text-indigo-700">{formatMinutes(calc.extra)}</p></div>
                        </div>
                        {entry.notes && <p className="text-xs text-slate-500 italic flex gap-2"><FileText className="w-3.5 h-3.5" /> {entry.notes}</p>}
                      </div>
                    );
                  })}
                  {workerEntries.length === 0 && <p className="text-center py-20 text-slate-400 italic">No hay jornadas este mes.</p>}
                </div>
              </div>
            )}

            {activeTab === 'balances' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleSaveCompensation} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Gestionar Compensación</h3>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase">Tipo</label>
                      <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-slate-200 border rounded-xl p-3 font-bold outline-none focus:ring-2 ring-indigo-500">
                        <option value="PAYMENT">Pago de Horas Extra</option>
                        <option value="REST_HOURS">Descanso (Horas)</option>
                        <option value="FREE_DAY">Día Libre (8h)</option>
