                        <tr>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Fecha</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Concepto</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Cantidad</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Acción</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {workerCompensations.map(c => (
                          <tr key={c.id}>
                            <td className="px-6 py-4 text-sm font-bold text-slate-700">{new Date(c.date).toLocaleDateString()}</td>
                            <td className="px-6 py-4">
                              <span className={`px-2 py-0.5 rounded text-[9px] font-black ${c.type === 'PAYMENT' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>{c.type}</span>
                              <p className="text-[10px] text-slate-400 italic mt-0.5">{c.notes}</p>
                            </td>
                            <td className="px-6 py-4 text-right font-black">{formatMinutes(c.minutes)}</td>
                            <td className="px-6 py-4 text-right">
                              <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 p-1 hover:bg-rose-50 rounded"><Trash2 className="w-4 h-4" /></button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'workers' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddWorker} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Empleado</h3>
                    <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-slate-200 border rounded-xl p-3 font-bold" placeholder="Nombre completo..." required />
                    <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl shadow-lg">Añadir al Equipo</button>
                  </form>
                </div>
                <div className="lg:col-span-2 space-y-2">
                  {workers.map(w => (
                    <div key={w.id} className={`flex items-center justify-between p-4 bg-white rounded-2xl border transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-indigo-100 ring-1 ring-indigo-600' : 'border-slate-200 shadow-sm'}`}>
                      <div className="flex items-center gap-3">
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                        <span className="font-bold">{w.name}</span>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => setSelectedWorkerId(w.id)} className="px-4 py-2 bg-slate-100 text-[10px] font-black uppercase rounded-lg hover:bg-slate-200 transition">Seleccionar</button>
                        <button onClick={() => handleDeleteWorker(w.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg"><Trash2 className="w-5 h-5" /></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'logs' && (
              <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-6">
                <h3 className="font-bold text-slate-800 mb-6">Historial de Auditoría</h3>
                <div className="space-y-4">
                  {workerEntries.flatMap(e => e.logs.map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                    <div key={log.id} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl flex gap-4">
                      <div className="bg-white p-2 rounded-lg border border-slate-200 h-fit"><History className="w-4 h-4 text-slate-400" /></div>
                      <div>
                        <p className="text-xs font-bold text-slate-800">Cambio en jornada {log.date}</p>
                        <p className="text-xs text-slate-600 mt-1">{log.field}: <span className="text-slate-400 line-through mx-1">{log.oldValue}</span> → <span className="font-bold text-indigo-600">{log.newValue}</span></p>
                        <p className="text-[10px] text-slate-400 mt-1 uppercase font-bold">{new Date(log.timestamp).toLocaleString()} - Por: {log.user}</p>
                      </div>
                    </div>
                  ))}
