      </main>

      {/* Nav Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-slate-200 flex justify-around p-3 md:hidden">
        {[{id:'daily', icon: Calendar}, {id:'balances', icon: ArrowRightLeft}, {id:'workers', icon: Users}, {id:'logs', icon: History}].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`p-2 rounded-xl ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50' : 'text-slate-400'}`}>
            <t.icon className="w-6 h-6" />
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X,
  Save,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- Persistencia con carga inicial robusta ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Juan Pérez' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || '');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Efectos de Sincronización Automática (Persistencia)
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- Helpers de cálculo ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- Handlers de acción ---
  const handleExportCSV = () => {
    if (!selectedWorker) return;

    // Header con BOM para compatibilidad Excel
    let csvContent = "\uFEFFFecha;Horas Brutas;Descuento Comida;Horas Netas;Horas Ordinarias;Horas Extra;Deficit;Notas\n";

    workerEntries.forEach(entry => {
      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
      const row = [
        entry.date,
        formatMinutes(entry.hoursBrutas),
        formatMinutes(entry.lunchDiscount),
        formatMinutes(calc.netas),
        formatMinutes(calc.ordinarias),
        formatMinutes(calc.extra),
        formatMinutes(calc.deficit),
        (entry.notes || "").replace(/;/g, ",").replace(/\n/g, " ")
      ].join(";");
      csvContent += row + "\n";
    });

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Control_Horario_${selectedWorker.name.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name: newWorkerName.trim()
    };
    const updated = [...workers, newWorker];
    setWorkers(updated);
    setNewWorkerName('');
    if (!selectedWorkerId) setSelectedWorkerId(newWorker.id);
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm(`¿Estás seguro de eliminar a ${workers.find(w => w.id === id)?.name}? Se perderán todos sus datos permanentemente.`)) {
      setWorkers(prev => prev.filter(w => w.id !== id));
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0]?.id || '');
    }
  };

  const resetEntryForm = () => {
    setEditingEntryId(null);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      startTime: '08:00',
      endTime: '17:00',
      hours: '08:00',
      lunch: '01:00',
      isLunchManual: false,
      notes: ''
    });
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;

    let brutas = 0;
    if (entryMode === 'direct') {
      brutas = parseHHMM(formData.hours);
    } else {
      const start = parseHHMM(formData.startTime);
      const end = parseHHMM(formData.endTime);
      brutas = end >= start ? end - start : (1440 - start) + end;
    }

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      const oldEntry = entries.find(e => e.id === editingEntryId);
      if (!oldEntry) return;

      const newLog: AuditLog = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'edición',
        oldValue: `${formatMinutes(oldEntry.hoursBrutas)} (${oldEntry.date})`,
        newValue: `${formatMinutes(brutas)} (${formData.date})`,
        user: 'admin'
      };

      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, isLunchManual: formData.isLunchManual, notes: formData.notes, logs: [...ent.logs, newLog] }
          : ent
      ));
      resetEntryForm();
    } else {
      const newEntry: TimeEntry = {
        id: Math.random().toString(36).substr(2, 9),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: [{
          id: Math.random().toString(36).substr(2, 9),
          timestamp: Date.now(),
          field: 'creación',
          oldValue: '-',
          newValue: 'nueva jornada',
          user: 'admin'
        }]
      };
      setEntries(prev => [...prev, newEntry]);
      setFormData(prev => ({ ...prev, notes: '' }));
    }
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00',
      endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteEntry = (id: string) => {
    if (confirm('¿Eliminar esta jornada definitivamente?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
      if (editingEntryId === id) resetEntryForm();
    }
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;

    if (compForm.id) {
      setCompensations(prev => prev.map(c => 
        c.id === compForm.id 
          ? { ...c, type: compForm.type, minutes: parseHHMM(compForm.minutes), notes: compForm.notes }
          : c
      ));
    } else {
      const newComp: CompensationEntry = {
        id: Math.random().toString(36).substr(2, 9),
        workerId: selectedWorkerId,
        date: new Date().toISOString().split('T')[0],
        type: compForm.type,
        minutes: parseHHMM(compForm.minutes),
        notes: compForm.notes
      };
      setCompensations(prev => [...prev, newComp]);
    }
    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

  // Fix: Implemented handleDeleteComp to resolve the error in line 526.
  const handleDeleteComp = (id: string) => {
    if (confirm('¿Eliminar este registro de compensación?')) {
      setCompensations(prev => prev.filter(c => c.id !== id));
    }
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Clock className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Control Horario Permanente</p>
          </div>
        </div>

        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select 
            value={selectedWorkerId}
            onChange={(e) => {
              setSelectedWorkerId(e.target.value);
              resetEntryForm();
            }}
            className="bg-transparent border-none rounded-md px-2 py-1 font-semibold text-slate-700 outline-none min-w-[180px]"
          >
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
            {workers.length === 0 && <option value="">Sin trabajadores</option>}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard de Totales */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-indigo-600 tracking-tight">{formatMinutes(totals.pendingExtra)}</span>
              <ArrowRightLeft className="text-indigo-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Déficit Acumulado</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-rose-500 tracking-tight">{formatMinutes(totals.totalDeficit)}</span>
              <AlertCircle className="text-rose-100 w-8 h-8" />
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Pagadas / Descansadas</p>
            <div className="flex items-center gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-slate-300">/</span>
              <span className="text-xl font-black text-blue-600">{formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Días Libres Usados</p>
            <div className="flex items-end justify-between">
              <span className="text-2xl font-black text-slate-800 tracking-tight">{totals.freeDaysCount}</span>
              <Coffee className="text-amber-100 w-8 h-8" />
            </div>
          </div>
        </div>

        {/* Navegación por Pestañas */}
        <div className="flex overflow-x-auto border-b border-slate-200 no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensación', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-6 py-4 font-bold text-sm transition-all border-b-2 whitespace-nowrap ${
                activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/30' : 'border-transparent text-slate-500 hover:text-slate-800'
              }`}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Contenido dinámico */}
        {!selectedWorkerId && activeTab !== 'workers' ? (
          <div className="bg-white p-12 rounded-3xl border-2 border-dashed border-slate-200 text-center">
             <Users className="w-16 h-16 text-slate-200 mx-auto mb-4" />
             <h2 className="text-xl font-bold text-slate-800">No hay trabajadores</h2>
             <button onClick={() => setActiveTab('workers')} className="mt-4 bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg">Crear primer trabajador</button>
          </div>
        ) : (
          <>
            {activeTab === 'daily' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddEntry} className={`bg-white p-6 rounded-2xl border transition-all shadow-sm space-y-4 ${editingEntryId ? 'border-amber-400 ring-4 ring-amber-50' : 'border-slate-200'}`}>
                    <div className="flex justify-between items-center">
                      <h3 className="font-bold text-slate-800 flex items-center gap-2">
                        {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                        {editingEntryId ? 'Editar registro' : 'Nueva jornada'}
                      </h3>
                      {editingEntryId && <button type="button" onClick={resetEntryForm} className="text-rose-500"><X /></button>}
                    </div>

                    <div className="flex p-1 bg-slate-100 rounded-xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition ${entryMode === 'clock' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Inicio/Fin</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition ${entryMode === 'direct' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Manual</button>
                    </div>

                    <div className="space-y-4">
                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase">Fecha</label>
                        <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 focus:ring-2 ring-indigo-500 outline-none font-bold" required />
                      </div>

                      {entryMode === 'clock' ? (
                        <div className="grid grid-cols-2 gap-3">
                          <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-slate-200 border rounded-xl p-3 font-bold" />
                          <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-slate-200 border rounded-xl p-3 font-bold" />
                        </div>
                      ) : (
                        <input type="text" placeholder="hh:mm" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-bold" />
                      )}

                      <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase">Comida</p>
                          <input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-20 bg-transparent text-lg font-black text-slate-700 outline-none" />
                        </div>
                        <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${formData.isLunchManual ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>
                          {formData.isLunchManual ? 'Manual' : 'Auto'}
                        </button>
                      </div>

                      <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 h-20 text-sm" placeholder="Notas..." />

                      <button type="submit" className={`w-full py-4 rounded-xl text-white font-bold shadow-lg transition-all ${editingEntryId ? 'bg-amber-600 hover:bg-amber-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                        {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                      </button>
                    </div>
                  </form>
                </div>

                <div className="lg:col-span-2 space-y-4">
                  <div className="flex justify-between items-center mb-2 px-2">
                    <h3 className="font-bold text-slate-800">Historial de Jornadas</h3>
                    <button onClick={handleExportCSV} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 hover:bg-emerald-700 transition">
                      <Download className="w-4 h-4" /> Exportar Excel
                    </button>
                  </div>

                  {workerEntries.map(entry => {
                    const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                    return (
                      <div key={entry.id} className={`bg-white p-5 rounded-2xl border transition-all shadow-sm ${editingEntryId === entry.id ? 'border-amber-400 bg-amber-50/10' : 'border-slate-200 hover:border-indigo-200'}`}>
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <span className="text-sm font-black text-slate-800">{new Date(entry.date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                            <p className="text-[9px] text-slate-400 font-bold uppercase mt-0.5">ID: {entry.id}</p>
                          </div>
                          <div className="flex gap-2">
                            {calc.extra > 0 && <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-[10px] font-black">+{formatMinutes(calc.extra)} EXTR</span>}
                            {calc.deficit > 0 && <span className="bg-rose-100 text-rose-700 px-3 py-1 rounded-full text-[10px] font-black">-{formatMinutes(calc.deficit)} DÉF</span>}
                            <div className="flex gap-1 ml-2">
                              <button onClick={() => handleEditEntry(entry)} className="p-1.5 text-amber-500 hover:bg-amber-50 rounded-lg"><Edit2 className="w-4 h-4" /></button>
                              <button onClick={() => handleDeleteEntry(entry.id)} className="p-1.5 text-rose-500 hover:bg-rose-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                            </div>
                          </div>
                        </div>
                        <div className="grid grid-cols-4 gap-4 py-3 border-y border-slate-100 mb-3 text-center">
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Bruta</p><p className="font-bold text-slate-700">{formatMinutes(entry.hoursBrutas)}</p></div>
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Comida</p><p className="font-bold text-slate-700">{formatMinutes(entry.lunchDiscount)}</p></div>
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Neta</p><p className="font-black text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                          <div><p className="text-[8px] font-black text-slate-400 uppercase">Extra</p><p className="font-black text-indigo-700">{formatMinutes(calc.extra)}</p></div>
                        </div>
                        {entry.notes && <p className="text-xs text-slate-500 italic flex gap-2"><FileText className="w-3.5 h-3.5" /> {entry.notes}</p>}
                      </div>
                    );
                  })}
                  {workerEntries.length === 0 && <p className="text-center py-20 text-slate-400 italic">No hay jornadas este mes.</p>}
                </div>
              </div>
            )}

            {activeTab === 'balances' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1">
                  <form onSubmit={handleSaveCompensation} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
                    <h3 className="font-bold text-slate-800 flex items-center gap-2 mb-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Gestionar Compensación</h3>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase">Tipo</label>
                      <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-slate-200 border rounded-xl p-3 font-bold outline-none focus:ring-2 ring-indigo-500">
                        <option value="PAYMENT">Pago de Horas Extra</option>
                        <option value="REST_HOURS">Descanso (Horas)</option>
                        <option value="FREE_DAY">Día Libre (8h)</option>
                      </select>
                    </div>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase">Cantidad (hh:mm)</label>
                      <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 font-bold" />
                    </div>
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-slate-200 border rounded-xl p-3 h-24 text-sm" placeholder="Motivo (ej: Vacaciones, Pago extra en nómina...)" />
                    <button type="submit" className="w-full bg-slate-800 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-black transition">Registrar Movimiento</button>
                  </form>
                </div>
                <div className="lg:col-span-2">
                  <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                    <table className="w-full text-left">
                      <thead className="bg-slate-50 border-b border-slate-100">
                        <tr>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Fecha</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Concepto</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Cantidad</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Acción</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {workerCompensations.map(c => (
                          <tr key={c.id}>
                            <td className="px-6 py-4 text-sm font-bold text-slate-700">{new Date(c.date).toLocaleDateString()}</td>
                            <td className="px-6 py-4">
                              <span className={`px-2 py-0.5 rounded text-[9px] font-black ${c.type === 'PAYMENT' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>{c.type}</span>
                              <p className="text-[10px] text-slate-400 italic mt-0.5">{c.notes}</p>
                            </td>
                            <td className="px-6 py-4 text-right font-black">{formatMinutes(c.minutes)}</td>
                            <td className="px-6 py-4 text-right">
                              <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 p-1 hover:bg-rose-50 rounded"><Trash2 className="w-4 h-4" /></button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'workers' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
