                <div className="space-y-4">
                  {workerEntries.flatMap(e => e.logs.map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                    <div key={log.id} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl flex gap-4">
                      <div className="bg-white p-2 rounded-lg border border-slate-200 h-fit"><History className="w-4 h-4 text-slate-400" /></div>
                      <div>
                        <p className="text-xs font-bold text-slate-800">Cambio en jornada {log.date}</p>
                        <p className="text-xs text-slate-600 mt-1">{log.field}: <span className="text-slate-400 line-through mx-1">{log.oldValue}</span> → <span className="font-bold text-indigo-600">{log.newValue}</span></p>
                        <p className="text-[10px] text-slate-400 mt-1 uppercase font-bold">{new Date(log.timestamp).toLocaleString()} - Por: {log.user}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </>
        )}
      </main>

      {/* Nav Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-slate-200 flex justify-around p-3 md:hidden">
        {[{id:'daily', icon: Calendar}, {id:'balances', icon: ArrowRightLeft}, {id:'workers', icon: Users}, {id:'logs', icon: History}].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`p-2 rounded-xl ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50' : 'text-slate-400'}`}>
            <t.icon className="w-6 h-6" />
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X,
  Save,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- CARGA INICIAL DESDE LOCALSTORAGE ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Trabajador por Defecto' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    const lastWorker = localStorage.getItem('tw_last_worker');
    return lastWorker || (workers[0]?.id || '');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // --- EFECTOS DE GUARDADO AUTOMÁTICO ---
  // Estos efectos se disparan ante cualquier cambio en los estados, asegurando persistencia real.
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- MEMOIZED DATA ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId), 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- HANDLERS ---
  const handleExportCSV = () => {
    if (!selectedWorker) return;

    // Header con BOM para compatibilidad total con Excel (caracteres españoles)
    let csvContent = "\uFEFFFecha;Horas Brutas;Descuento Comida;Horas Netas;Horas Ordinarias;Horas Extra;Déficit;Notas\n";

    workerEntries.forEach(entry => {
      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
      const row = [
        entry.date,
        formatMinutes(entry.hoursBrutas),
        formatMinutes(entry.lunchDiscount),
        formatMinutes(calc.netas),
        formatMinutes(calc.ordinarias),
        formatMinutes(calc.extra),
        formatMinutes(calc.deficit),
        (entry.notes || "").replace(/;/g, ",").replace(/\n/g, " ")
      ].join(";");
      csvContent += row + "\n";
    });

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Reporte_Horas_${selectedWorker.name.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: Math.random().toString(36).substr(2, 9),
      name: newWorkerName.trim()
    };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
    if (!selectedWorkerId) setSelectedWorkerId(newWorker.id);
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm(`¿Estás seguro de eliminar a ${workers.find(w => w.id === id)?.name}? Todos sus registros se perderán.`)) {
      setWorkers(prev => prev.filter(w => w.id !== id));
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0]?.id || '');
    }
  };

  const resetEntryForm = () => {
    setEditingEntryId(null);
    setFormData(prev => ({
      ...prev,
      hours: '08:00',
      lunch: '01:00',
      isLunchManual: false,
      notes: ''
    }));
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;

    let brutas = 0;
    if (entryMode === 'direct') {
      brutas = parseHHMM(formData.hours);
    } else {
      const start = parseHHMM(formData.startTime);
      const end = parseHHMM(formData.endTime);
      brutas = end >= start ? end - start : (1440 - start) + end;
    }

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      const oldEntry = entries.find(e => e.id === editingEntryId);
      if (!oldEntry) return;

      const newLog: AuditLog = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        field: 'edición jornada',
        oldValue: `${formatMinutes(oldEntry.hoursBrutas)} el ${oldEntry.date}`,
        newValue: `${formatMinutes(brutas)} el ${formData.date}`,
        user: 'admin'
      };

      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, isLunchManual: formData.isLunchManual, notes: formData.notes, logs: [...ent.logs, newLog] }
          : ent
      ));
      resetEntryForm();
    } else {
      const newEntry: TimeEntry = {
        id: Math.random().toString(36).substr(2, 9),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: [{
          id: Math.random().toString(36).substr(2, 9),
          timestamp: Date.now(),
          field: 'creación',
          oldValue: '-',
          newValue: 'nueva entrada',
          user: 'admin'
        }]
      };
      setEntries(prev => [...prev, newEntry]);
      setFormData(prev => ({ ...prev, notes: '' }));
    }
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00',
      endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteEntry = (id: string) => {
    if (confirm('¿Eliminar esta jornada definitivamente?')) {
      setEntries(prev => prev.filter(e => e.id !== id));
      if (editingEntryId === id) resetEntryForm();
    }
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedWorkerId) return;

    const newComp: CompensationEntry = {
      id: Math.random().toString(36).substr(2, 9),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations(prev => [...prev, newComp]);
    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

  const handleDeleteComp = (id: string) => {
    if (confirm('¿Eliminar este registro de compensación?')) {
      setCompensations(prev => prev.filter(c => c.id !== id));
    }
  };

  return (
    <div className="min-h-screen pb-20 text-slate-900 bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Clock className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="inline-block w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
              Auto-guardado activo
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-xl border border-slate-200 shadow-inner">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select 
            value={selectedWorkerId}
            onChange={(e) => {
              setSelectedWorkerId(e.target.value);
              resetEntryForm();
            }}
            className="bg-transparent border-none rounded-md px-2 py-1 font-semibold text-slate-700 outline-none min-w-[200px]"
          >
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
            {workers.length === 0 && <option value="">Crear trabajador...</option>}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Resumen de Bolsas */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm transition-all hover:shadow-md border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Horas Extra Pendientes</p>
            <div className="flex items-end justify-between">
              <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pendingExtra)}</span>
              <ArrowRightLeft className="text-indigo-100 w-10 h-10" />
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm transition-all hover:shadow-md border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Déficit de Jornada</p>
            <div className="flex items-end justify-between">
              <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.totalDeficit)}</span>
              <AlertCircle className="text-rose-100 w-10 h-10" />
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm transition-all hover:shadow-md border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Total Pagado / Descanso</p>
            <div className="flex items-center gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-slate-200 font-thin text-3xl">/</span>
              <span className="text-xl font-black text-blue-600">{formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm transition-all hover:shadow-md border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Días Libres Disfrutados</p>
            <div className="flex items-end justify-between">
              <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.freeDaysCount}</span>
              <Coffee className="text-amber-100 w-10 h-10" />
            </div>
          </div>
        </div>

        {/* Pestañas de Navegación */}
        <div className="flex overflow-x-auto border-b border-slate-200 no-scrollbar bg-white rounded-t-3xl px-4">
          {[
            { id: 'daily', label: 'Jornadas Diarias', icon: Calendar },
            { id: 'balances', label: 'Gestión Saldo', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Historial/Logs', icon: History }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-6 py-5 font-bold text-sm transition-all border-b-4 whitespace-nowrap ${
                activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500 hover:text-slate-800'
              }`}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>

        {/* Vistas Dinámicas */}
        {!selectedWorkerId && activeTab !== 'workers' ? (
          <div className="bg-white p-20 rounded-3xl border-2 border-dashed border-slate-200 text-center shadow-sm">
             <Users className="w-20 h-20 text-slate-200 mx-auto mb-6" />
             <h2 className="text-2xl font-black text-slate-800">No hay trabajadores registrados</h2>
             <p className="text-slate-500 mt-2 mb-8">Debes añadir al menos un perfil para empezar a registrar horas.</p>
             <button onClick={() => setActiveTab('workers')} className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Configurar Equipo Ahora</button>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            {activeTab === 'daily' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Formulario de Entrada */}
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-3xl border transition-all shadow-sm space-y-6 ${editingEntryId ? 'border-amber-400 ring-4 ring-amber-50' : 'border-slate-200'}`}>
                    <div className="flex justify-between items-center">
                      <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                        {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                        {editingEntryId ? 'Modificar Registro' : 'Registrar Jornada'}
                      </h3>
                      {editingEntryId && <button type="button" onClick={resetEntryForm} className="text-rose-500 p-2 hover:bg-rose-50 rounded-full transition"><X /></button>}
                    </div>

                    <div className="flex p-1.5 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2.5 text-xs font-black rounded-xl transition-all ${entryMode === 'clock' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Inicio / Fin</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2.5 text-xs font-black rounded-xl transition-all ${entryMode === 'direct' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Horas Totales</button>
                    </div>

                    <div className="space-y-5">
                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Fecha de trabajo</label>
                        <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 focus:ring-4 ring-indigo-50 outline-none font-bold text-slate-700" required />
                      </div>

                      {entryMode === 'clock' ? (
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Entrada</label>
                            <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 font-bold text-slate-700" />
                          </div>
                          <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Salida</label>
                            <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 font-bold text-slate-700" />
                          </div>
                        </div>
                      ) : (
                        <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tiempo total (hh:mm)</label>
                          <input type="text" placeholder="08:30" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 font-bold text-slate-700" />
                        </div>
                      )}

                      <div className="bg-indigo-50/50 p-5 rounded-3xl border border-indigo-100 flex items-center justify-between">
                        <div>
                          <p className="text-[10px] font-black text-indigo-400 uppercase">Tiempo de Comida</p>
                          <input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-24 bg-transparent text-xl font-black text-indigo-700 outline-none" />
                        </div>
                        <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase shadow-sm border transition-all ${formData.isLunchManual ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-white text-indigo-600 border-indigo-200'}`}>
                          {formData.isLunchManual ? 'Manual' : 'Automático'}
                        </button>
                      </div>

                      <div>
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Observaciones</label>
                        <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 h-24 text-sm font-medium focus:ring-4 ring-indigo-50 outline-none" placeholder="Motivo de las horas extra, incidencias..." />
                      </div>

                      <button type="submit" className={`w-full py-5 rounded-2xl text-white font-black shadow-xl transition-all transform active:scale-95 ${editingEntryId ? 'bg-amber-600 hover:bg-amber-700 shadow-amber-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}>
                        {editingEntryId ? 'Guardar Cambios' : 'Confirmar Registro'}
                      </button>
                    </div>
                  </form>
                </div>

                {/* Listado de Jornadas */}
                <div className="lg:col-span-2 space-y-6">
                  <div className="flex justify-between items-center mb-4 px-4">
                    <h3 className="font-black text-slate-800 text-xl flex items-center gap-2">
                       <History className="text-indigo-600" /> Registros Recientes
                    </h3>
                    <button onClick={handleExportCSV} className="bg-emerald-600 text-white px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2 hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-50 active:scale-95">
                      <Download className="w-4 h-4" /> Exportar a Excel
                    </button>
                  </div>

                  {workerEntries.map(entry => {
                    const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                    return (
                      <div key={entry.id} className={`bg-white p-6 rounded-3xl border-2 transition-all shadow-sm group ${editingEntryId === entry.id ? 'border-amber-400 bg-amber-50/10' : 'border-slate-100 hover:border-indigo-100 hover:shadow-md'}`}>
                        <div className="flex justify-between items-start mb-6">
                          <div>
                            <span className="text-sm font-black text-slate-800 bg-slate-100 px-3 py-1 rounded-lg">{new Date(entry.date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
                            <p className="text-[9px] text-slate-400 font-bold uppercase mt-2 tracking-widest">REG: {entry.id}</p>
                          </div>
                          <div className="flex gap-2">
                            {calc.extra > 0 && <span className="bg-indigo-600 text-white px-4 py-1.5 rounded-2xl text-[10px] font-black shadow-lg shadow-indigo-100">+{formatMinutes(calc.extra)} EXTRA</span>}
                            {calc.deficit > 0 && <span className="bg-rose-500 text-white px-4 py-1.5 rounded-2xl text-[10px] font-black shadow-lg shadow-rose-100">-{formatMinutes(calc.deficit)} DÉFICIT</span>}
                            <div className="flex gap-1 ml-4 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={() => handleEditEntry(entry)} className="p-2 text-amber-500 hover:bg-amber-50 rounded-xl" title="Editar"><Edit2 className="w-4 h-4" /></button>
                              <button onClick={() => handleDeleteEntry(entry.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl" title="Borrar"><Trash2 className="w-4 h-4" /></button>
                            </div>
                          </div>
                        </div>

                        <div className="grid grid-cols-4 gap-6 py-5 border-y border-slate-50 mb-5 text-center">
                          <div>
                            <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Bruta</p>
                            <p className="font-black text-slate-700 text-lg">{formatMinutes(entry.hoursBrutas)}</p>
                          </div>
                          <div>
                            <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Comida</p>
                            <p className="font-black text-slate-500 text-lg">{formatMinutes(entry.lunchDiscount)}</p>
                          </div>
                          <div>
                            <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Neta Calc.</p>
                            <p className="font-black text-indigo-600 text-xl">{formatMinutes(calc.netas)}</p>
                          </div>
                          <div>
                            <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Ordinaria</p>
                            <p className="font-black text-slate-800 text-lg">{formatMinutes(calc.ordinarias)}</p>
                          </div>
                        </div>

                        <div className="flex items-center gap-4">
                           <div className="flex-1 text-xs font-bold text-slate-400 bg-slate-50 px-4 py-3 rounded-2xl border border-slate-100 italic">
                             {calc.explanation}
                           </div>
                           {entry.notes && (
                             <div className="flex items-center gap-2 text-xs font-medium text-slate-600 bg-amber-50 px-4 py-3 rounded-2xl border border-amber-100 max-w-[40%] truncate">
                               <FileText className="w-3.5 h-3.5 text-amber-500" /> {entry.notes}
                             </div>
                           )}
                        </div>
                      </div>
                    );
                  })}
                  {workerEntries.length === 0 && (
                    <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-100">
                      <Calendar className="w-16 h-16 text-slate-100 mx-auto mb-4" />
                      <p className="text-slate-400 font-bold">No hay actividad registrada este periodo.</p>
                    </div>
                  )}
                </div>
              </div>
            )}

            {activeTab === 'balances' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Formulario Compensación */}
                <div className="lg:col-span-1">
                  <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm space-y-6">
                    <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Nueva Compensación</h3>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo de acción</label>
                      <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-slate-200 border-2 rounded-2xl p-4 font-bold outline-none focus:ring-4 ring-indigo-50">
                        <option value="PAYMENT">💰 Pago en Nómina (Horas Extra)</option>
                        <option value="REST_HOURS">🏖️ Compensación por Descanso (Horas)</option>
                        <option value="FREE_DAY">📅 Día Libre Completo (8h)</option>
                      </select>
                    </div>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tiempo a deducir (hh:mm)</label>
                      <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 font-black text-slate-700" placeholder="01:30" />
                    </div>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Justificante / Motivo</label>
                      <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-slate-200 border-2 rounded-2xl p-4 h-28 text-sm font-medium" placeholder="Referencia de pago, fecha de vacaciones..." />
                    </div>
                    <button type="submit" className="w-full bg-slate-800 text-white font-black py-5 rounded-2xl shadow-xl hover:bg-black transition-all active:scale-95">Aplicar al Saldo</button>
                  </form>
                </div>
                {/* Historial Compensaciones */}
                <div className="lg:col-span-2">
                  <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
                      <h3 className="font-black text-slate-800">Historial de Movimientos</h3>
                    </div>
                    <div className="overflow-x-auto">
                      <table className="w-full text-left">
                        <thead className="bg-slate-50/50">
                          <tr>
                            <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                            <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Concepto</th>
                            <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                            <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Control</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                          {workerCompensations.map(c => (
                            <tr key={c.id} className="hover:bg-slate-50/30 transition-colors">
                              <td className="px-8 py-5 text-sm font-black text-slate-600">{new Date(c.date).toLocaleDateString()}</td>
                              <td className="px-8 py-5">
                                <span className={`px-3 py-1 rounded-lg text-[9px] font-black border ${c.type === 'PAYMENT' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-blue-50 text-blue-700 border-blue-100'}`}>{c.type}</span>
                                <p className="text-[11px] text-slate-400 font-medium mt-1.5 line-clamp-1">{c.notes || "Sin descripción"}</p>
                              </td>
                              <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                              <td className="px-8 py-5 text-right">
                                <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 p-2 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
                              </td>
                            </tr>
                          ))}
                          {workerCompensations.length === 0 && (
                            <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No se han aplicado compensaciones todavía.</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'workers' && (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Formulario Trabajador */}
                <div className="lg:col-span-1">
                  <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm space-y-6">
                    <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Añadir Miembro</h3>
                    <p className="text-xs text-slate-500">Crea un perfil separado para cada empleado para llevar un control individualizado.</p>
                    <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nombre Completo</label>
                      <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-slate-200 border-2 rounded-2xl p-4 font-black" placeholder="Ej: Elena Rodríguez" required />
                    </div>
                    <button type="submit" className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-50 active:scale-95">Añadir Trabajador</button>
                  </form>
                </div>
                {/* Lista Trabajadores */}
                <div className="lg:col-span-2 space-y-3">
                  <h3 className="font-black text-slate-800 text-xl px-2 mb-4">Plantilla Actual</h3>
                  {workers.map(w => (
                    <div key={w.id} className={`flex items-center justify-between p-5 bg-white rounded-3xl border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-indigo-100 ring-4 ring-indigo-50' : 'border-slate-100 shadow-sm'}`}>
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg transition-colors ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                        <div>
                           <span className="font-black text-slate-800 block">{w.name}</span>
                           <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">ID Empleado: {w.id}</span>
                        </div>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => setSelectedWorkerId(w.id)} className={`px-5 py-2.5 text-[10px] font-black uppercase rounded-xl transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                          {selectedWorkerId === w.id ? 'Seleccionado' : 'Cambiar a este'}
                        </button>
                        <button onClick={() => handleDeleteWorker(w.id)} className="p-3 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'logs' && (
              <div className="bg-white rounded-3xl border border-slate-200 shadow-sm p-8">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="font-black text-slate-800 text-xl">Libro de Auditoría Permanente</h3>
                  <span className="bg-slate-100 text-slate-400 text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest">Trazabilidad Total</span>
                </div>
                <div className="space-y-4">
                  {workerEntries.flatMap(e => e.logs.map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                    <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start">
                      <div className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm"><History className="w-5 h-5 text-slate-300" /></div>
                      <div className="flex-1">
                        <div className="flex justify-between items-center mb-1.5">
                           <p className="text-[11px] font-black text-indigo-600 uppercase">Cambio en jornada: {log.date}</p>
                           <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                        </div>
                        <p className="text-sm text-slate-700 font-bold">
                          Campo <span className="text-indigo-400">{log.field}</span> modificado: 
                          <span className="text-slate-300 line-through mx-2 font-medium italic">"{log.oldValue}"</span> 
                          <ArrowRightLeft className="w-3 h-3 inline text-slate-300 mx-1" />
                          <span className="font-black text-slate-900 ml-2">"{log.newValue}"</span>
                        </p>
                        <p className="text-[10px] text-slate-400 mt-2 font-black uppercase tracking-tighter">Usuario: {log.user}</p>
                      </div>
                    </div>
                  ))}
                  {workerEntries.length === 0 && <p className="text-center py-20 text-slate-300 italic font-medium">Sin registros históricos.</p>}
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Navegación Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex justify-around p-4 md:hidden shadow-2xl z-50">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Saldo'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 p-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 scale-105' : 'text-slate-400'}`}>
            <t.icon className="w-6 h-6" />
            <span className="text-[8px] font-black uppercase">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X,
  Save,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- CARGA SÍNCRONA PARA EVITAR BORRADOS AL ARRANCAR ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    try {
      const saved = localStorage.getItem('tw_workers');
      return saved ? JSON.parse(saved) : [{ id: '1', name: 'Trabajador Principal' }];
    } catch { return [{ id: '1', name: 'Trabajador Principal' }]; }
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_entries');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_compensations');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || '1');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // --- PERSISTENCIA ATÓMICA ---
  // Guardamos inmediatamente después de cada cambio real
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- DATOS DERIVADOS ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId) || workers[0], 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- ACCIONES ---
  const handleExportCSV = () => {
    if (!selectedWorker) return;
    let csvContent = "\uFEFFFecha;Horas Brutas;Comida;Horas Netas;Horas Ordinarias;Horas Extra;Déficit;Notas\n";
    workerEntries.forEach(entry => {
      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
      csvContent += [
        entry.date,
        formatMinutes(entry.hoursBrutas),
        formatMinutes(entry.lunchDiscount),
        formatMinutes(calc.netas),
        formatMinutes(calc.ordinarias),
        formatMinutes(calc.extra),
        formatMinutes(calc.deficit),
        (entry.notes || "").replace(/;/g, ",")
      ].join(";") + "\n";
    });
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `Reporte_${selectedWorker.name}_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker = { id: Date.now().toString(), name: newWorkerName.trim() };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  const handleDeleteWorker = (id: string) => {
    if (confirm(`¿Eliminar permanentemente a este trabajador y sus datos?`)) {
      setWorkers(prev => prev.filter(w => w.id !== id));
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
    }
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const start = parseHHMM(formData.startTime);
        const end = parseHHMM(formData.endTime);
        return end >= start ? end - start : (1440 - start) + end;
      })();

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, isLunchManual: formData.isLunchManual, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: Date.now().toString(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: [{ id: Date.now().toString(), timestamp: Date.now(), field: 'creación', oldValue: '-', newValue: 'nueva', user: 'admin' }]
      };
      setEntries(prev => [...prev, newEntry]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const newComp: CompensationEntry = {
      id: Date.now().toString(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations(prev => [...prev, newComp]);
    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-bold">TimeGuard Pro</h1>
            <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> Datos Guardados Localmente
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-100 p-1.5 rounded-xl border">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-semibold text-slate-700 outline-none min-w-[180px]">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard de Totales */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600">{formatMinutes(totals.pendingExtra)}</span>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500">{formatMinutes(totals.totalDeficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Compensadas (P/D)</p>
            <div className="flex gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-xl font-black text-blue-600">/ {formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Días Libres</p>
            <span className="text-3xl font-black text-slate-800">{totals.freeDaysCount}</span>
          </div>
        </div>

        {/* Pestañas */}
        <div className="flex bg-white rounded-t-3xl border-b px-2 overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensación', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Historial', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-4 font-bold text-sm border-b-4 transition-all whitespace-nowrap ${activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        {/* Vistas */}
        <div className="animate-in fade-in duration-300">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-4">
                  <h3 className="font-black text-slate-800 flex items-center gap-2"><Plus className="w-5 h-5 text-indigo-600" /> Registrar Horas</h3>
                  <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border p-4 rounded-2xl font-bold" required />
                  <div className="flex p-1 bg-slate-100 rounded-xl">
                    <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-xs font-black rounded-lg ${entryMode === 'clock' ? 'bg-white shadow-sm' : ''}`}>Reloj</button>
                    <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-xs font-black rounded-lg ${entryMode === 'direct' ? 'bg-white shadow-sm' : ''}`}>Manual</button>
                  </div>
                  {entryMode === 'clock' ? (
                    <div className="grid grid-cols-2 gap-2">
                      <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border p-4 rounded-2xl font-bold" />
                      <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border p-4 rounded-2xl font-bold" />
                    </div>
                  ) : (
                    <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border p-4 rounded-2xl font-bold" placeholder="hh:mm" />
                  )}
                  <div className="bg-slate-50 p-4 rounded-2xl border flex justify-between items-center">
                    <div><p className="text-[10px] font-black uppercase text-slate-400">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-20 bg-transparent text-xl font-black outline-none" /></div>
                    <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className="text-[10px] font-black uppercase bg-white border px-3 py-1 rounded-full">{formData.isLunchManual ? 'Manual' : 'Auto'}</button>
                  </div>
                  <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border p-4 rounded-2xl text-sm" placeholder="Notas..." />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-lg">Guardar Registro</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-2">
                  <h3 className="font-black">Listado de Jornadas</h3>
                  <button onClick={handleExportCSV} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2"><Download className="w-4 h-4" /> Exportar</button>
                </div>
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex flex-col gap-4">
                      <div className="flex justify-between items-start">
                        <span className="font-black text-slate-700">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</span>
                        <div className="flex gap-1">
                          <button onClick={() => { setEditingEntryId(entry.id); setFormData({ ...formData, date: entry.date, hours: formatMinutes(entry.hoursBrutas), notes: entry.notes || '' }); setEntryMode('direct'); }} className="p-2 text-amber-500 hover:bg-amber-50 rounded-lg"><Edit2 className="w-4 h-4" /></button>
                          <button onClick={() => { if(confirm('¿Borrar?')) setEntries(prev => prev.filter(e => e.id !== entry.id)) }} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-2 text-center border-y py-4">
                        <div><p className="text-[9px] font-black text-slate-400">BRUTA</p><p className="font-bold">{formatMinutes(entry.hoursBrutas)}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400">NETA</p><p className="font-black text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400">EXTRA</p><p className="font-black text-emerald-600">{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400">DÉFICIT</p><p className="font-black text-rose-500">{formatMinutes(calc.deficit)}</p></div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-6 rounded-3xl border space-y-4">
                  <h3 className="font-black flex items-center gap-2"><ArrowRightLeft className="w-5 h-5" /> Compensación</h3>
                  <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border p-4 rounded-2xl font-bold">
                    <option value="PAYMENT">Pago Extra</option>
                    <option value="REST_HOURS">Descanso (Horas)</option>
                    <option value="FREE_DAY">Día Libre</option>
                  </select>
                  <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border p-4 rounded-2xl font-bold" />
                  <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border p-4 rounded-2xl text-sm" placeholder="Motivo..." />
                  <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl">Aplicar Movimiento</button>
                </form>
              </div>
              <div className="lg:col-span-2">
                <div className="bg-white rounded-3xl border overflow-hidden">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50">
                      <tr>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Fecha</th>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Tipo</th>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Cantidad</th>
                        <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Borrar</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y">
                      {workerCompensations.map(c => (
                        <tr key={c.id}>
                          <td className="px-6 py-4 text-sm font-bold">{new Date(c.date).toLocaleDateString()}</td>
                          <td className="px-6 py-4 text-xs font-bold text-indigo-600">{c.type}</td>
                          <td className="px-6 py-4 text-right font-black">{formatMinutes(c.minutes)}</td>
                          <td className="px-6 py-4 text-right"><button onClick={() => setCompensations(prev => prev.filter(x => x.id !== c.id))} className="text-rose-500"><Trash2 className="w-4 h-4" /></button></td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-6 rounded-3xl border space-y-4">
                  <h3 className="font-black flex items-center gap-2"><UserPlus className="w-5 h-5" /> Nuevo Trabajador</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border p-4 rounded-2xl font-bold" placeholder="Nombre..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl">Añadir</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-2">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-4 bg-white rounded-2xl border ${selectedWorkerId === w.id ? 'border-indigo-600' : ''}`}>
                    <span className="font-bold">{w.name}</span>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className="px-4 py-2 bg-slate-100 rounded-lg text-xs font-bold">Seleccionar</button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="text-rose-500 p-2"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-3xl border p-6 space-y-4">
               <h3 className="font-black text-xl mb-4">Registro de Cambios</h3>
               {workerEntries.flatMap(e => e.logs.map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                 <div key={log.id} className="p-4 bg-slate-50 rounded-2xl border text-sm">
                   <p className="font-bold text-indigo-600">Jornada {log.date}</p>
                   <p className="text-slate-500">{new Date(log.timestamp).toLocaleString()}</p>
                   <p className="mt-2">Campo <span className="font-bold">{log.field}</span>: {log.oldValue} → <span className="font-black text-slate-800">{log.newValue}</span></p>
                 </div>
               ))}
            </div>
          )}
        </div>
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t flex justify-around p-4 md:hidden z-50">
        {[ {id:'daily', icon: Calendar}, {id:'balances', icon: ArrowRightLeft}, {id:'workers', icon: Users}, {id:'logs', icon: History} ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`p-2 rounded-xl ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50' : 'text-slate-400'}`}>
            <t.icon className="w-6 h-6" />
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X,
  Save,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const App: React.FC = () => {
  // --- CARGA INICIAL ROBUSTA ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    try {
      const saved = localStorage.getItem('tw_workers');
      return saved ? JSON.parse(saved) : [{ id: '1', name: 'Trabajador Principal' }];
    } catch { return [{ id: '1', name: 'Trabajador Principal' }]; }
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_entries');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_compensations');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || '1');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // --- PERSISTENCIA AUTOMÁTICA ---
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- LÓGICA DE FILTRADO ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId) || workers[0], 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- ACCIONES DE GESTIÓN ---
  const handleExportCSV = () => {
    if (!selectedWorker) return;
    let csvContent = "\uFEFFFecha;Horas Brutas;Comida;Horas Netas;Horas Ordinarias;Horas Extra;Déficit;Notas\n";
    workerEntries.forEach(entry => {
      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
      csvContent += [
        entry.date,
        formatMinutes(entry.hoursBrutas),
        formatMinutes(entry.lunchDiscount),
        formatMinutes(calc.netas),
        formatMinutes(calc.ordinarias),
        formatMinutes(calc.extra),
        formatMinutes(calc.deficit),
        (entry.notes || "").replace(/;/g, ",")
      ].join(";") + "\n";
    });
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `Reporte_${selectedWorker.name}_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker = { id: Date.now().toString(), name: newWorkerName.trim() };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  const handleDeleteWorker = (id: string) => {
    if (workers.length <= 1) {
      alert("No puedes eliminar al último trabajador.");
      return;
    }
    if (confirm(`¿Eliminar permanentemente a ${workers.find(w => w.id === id)?.name}? Se borrarán todas sus jornadas y compensaciones.`)) {
      setWorkers(prev => prev.filter(w => w.id !== id));
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers[0].id);
    }
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const start = parseHHMM(formData.startTime);
        const end = parseHHMM(formData.endTime);
        return end >= start ? end - start : (1440 - start) + end;
      })();

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, isLunchManual: formData.isLunchManual, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: Date.now().toString(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: [{ id: Date.now().toString(), timestamp: Date.now(), field: 'creación', oldValue: '-', newValue: 'nueva', user: 'admin' }]
      };
      setEntries(prev => [...prev, newEntry]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00',
      endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteEntry = (id: string) => {
    if (confirm("¿Estás seguro de eliminar este registro de jornada?")) {
      setEntries(prev => prev.filter(e => e.id !== id));
      if (editingEntryId === id) setEditingEntryId(null);
    }
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const newComp: CompensationEntry = {
      id: Date.now().toString(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations(prev => [...prev, newComp]);
    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

  const handleDeleteComp = (id: string) => {
    if (confirm("¿Eliminar este movimiento de compensación?")) {
      setCompensations(prev => prev.filter(c => c.id !== id));
    }
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-bold text-slate-800">TimeGuard Pro</h1>
            <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Persistencia Activo
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[180px]">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Dashboard de Estado */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <div className="flex items-baseline gap-2">
              <span className="text-3xl font-black text-indigo-600">{formatMinutes(totals.pendingExtra)}</span>
              <span className="text-xs text-slate-400 font-bold">pendientes</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Déficit de Horas</p>
            <span className="text-3xl font-black text-rose-500">{formatMinutes(totals.totalDeficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Pagadas / Descansadas</p>
            <div className="flex gap-2 items-baseline">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-xl font-black text-blue-600">/ {formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Días Libres Usados</p>
            <span className="text-3xl font-black text-slate-800">{totals.freeDaysCount}</span>
          </div>
        </div>

        {/* Navegación de Pestañas */}
        <div className="flex bg-white rounded-t-3xl border-b border-slate-200 px-2 overflow-x-auto no-scrollbar shadow-sm">
          {[
            { id: 'daily', label: 'Registros Diarios', icon: Calendar },
            { id: 'balances', label: 'Compensaciones', icon: ArrowRightLeft },
            { id: 'workers', label: 'Gestionar Plantilla', icon: Users },
            { id: 'logs', label: 'Historial de Auditoría', icon: History }
          ].map(tab => (
