export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  Coffee,
  AlertCircle,
  UserPlus,
  Trash2,
  User,
  Timer,
  Edit2,
  X,
  Save,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

// Generador de ID más robusto para evitar duplicados que rompen el borrado
const generateId = () => {
  return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
};

const App: React.FC = () => {
  // --- CARGA INICIAL ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    try {
      const saved = localStorage.getItem('tw_workers');
      return saved ? JSON.parse(saved) : [{ id: 'default-1', name: 'Trabajador Principal' }];
    } catch { return [{ id: 'default-1', name: 'Trabajador Principal' }]; }
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_entries');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_compensations');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    const last = localStorage.getItem('tw_last_worker');
    return last && last !== 'undefined' ? last : (workers[0]?.id || 'default-1');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // --- PERSISTENCIA AUTOMÁTICA ---
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- LÓGICA DE FILTRADO ---
  const selectedWorker = useMemo(() => 
    workers.find(w => w.id === selectedWorkerId) || workers[0], 
  [workers, selectedWorkerId]);

  const workerEntries = useMemo(() => 
    entries.filter(e => e.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => c.workerId === selectedWorkerId).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let totalExtraGenerated = 0;
    let totalDeficit = 0;
    let totalPaid = 0;
    let totalRested = 0;
    let freeDaysCount = 0;

    workerEntries.forEach(e => {
      const calc = calculateDay(e.hoursBrutas, e.lunchDiscount);
      totalExtraGenerated += calc.extra;
      totalDeficit += calc.deficit;
    });

    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') totalPaid += c.minutes;
      if (c.type === 'REST_HOURS') totalRested += c.minutes;
      if (c.type === 'FREE_DAY') {
        totalRested += c.minutes;
        freeDaysCount += 1;
      }
    });

    const pendingExtra = totalExtraGenerated - totalPaid - totalRested;
    return { totalExtraGenerated, totalDeficit, totalPaid, totalRested, pendingExtra, freeDaysCount };
  }, [workerEntries, workerCompensations]);

  // --- HANDLERS DE BORRADO (CORREGIDOS) ---
  const handleDeleteEntry = (id: string) => {
    if (window.confirm("¿Deseas eliminar este registro de jornada permanentemente?")) {
      setEntries(prev => prev.filter(entry => entry.id !== id));
      if (editingEntryId === id) setEditingEntryId(null);
    }
  };

  const handleDeleteComp = (id: string) => {
    if (window.confirm("¿Eliminar este registro de compensación?")) {
      setCompensations(prev => prev.filter(c => c.id !== id));
    }
  };

  const handleDeleteWorker = (id: string) => {
    if (workers.length <= 1) {
      alert("No puedes eliminar al único trabajador.");
      return;
    }
    if (window.confirm(`¿Eliminar a ${workers.find(w => w.id === id)?.name}? Se borrarán TODOS sus datos asociados.`)) {
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
      setWorkers(prev => prev.filter(w => w.id !== id));
      if (selectedWorkerId === id) setSelectedWorkerId(workers.find(w => w.id !== id)?.id || '');
    }
  };

  // --- OTROS HANDLERS ---
  const handleExportCSV = () => {
    if (!selectedWorker) return;
    let csvContent = "\uFEFFFecha;Horas Brutas;Comida;Horas Netas;Extra;Déficit;Notas\n";
    workerEntries.forEach(entry => {
      const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
      csvContent += [
        entry.date,
        formatMinutes(entry.hoursBrutas),
        formatMinutes(entry.lunchDiscount),
        formatMinutes(calc.netas),
        formatMinutes(calc.extra),
        formatMinutes(calc.deficit),
        (entry.notes || "").replace(/;/g, ",")
      ].join(";") + "\n";
    });
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `Horas_${selectedWorker.name}_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker = { id: generateId(), name: newWorkerName.trim() };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const start = parseHHMM(formData.startTime);
        const end = parseHHMM(formData.endTime);
        return end >= start ? end - start : (1440 - start) + end;
      })();

    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, isLunchManual: formData.isLunchManual, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: [{ id: generateId(), timestamp: Date.now(), field: 'creación', oldValue: '-', newValue: 'nueva', user: 'admin' }]
      };
      setEntries(prev => [...prev, newEntry]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00',
      endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: parseHHMM(compForm.minutes),
      notes: compForm.notes
    };
    setCompensations(prev => [...prev, newComp]);
    setCompForm({ id: null, type: 'PAYMENT', notes: '', minutes: '01:00' });
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-bold text-slate-800">TimeGuard Pro</h1>
            <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-widest flex items-center gap-1">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Almacenamiento Local Activo
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-2" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[180px]">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-6 space-y-6">
        {/* Resumen */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600">{formatMinutes(totals.pendingExtra)}</span>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Déficit Total</p>
            <span className="text-3xl font-black text-rose-500">{formatMinutes(totals.totalDeficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Compensado</p>
            <div className="flex gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.totalPaid)}</span>
              <span className="text-xl font-black text-blue-600">/ {formatMinutes(totals.totalRested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Días Libres</p>
            <span className="text-3xl font-black text-slate-800">{totals.freeDaysCount}</span>
          </div>
        </div>

        {/* Pestañas */}
        <div className="flex bg-white rounded-t-3xl border-b px-2 overflow-x-auto no-scrollbar shadow-sm">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensar', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-4 font-bold text-sm border-b-4 transition-all whitespace-nowrap ${activeTab === tab.id ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-3xl border shadow-sm space-y-5 ${editingEntryId ? 'border-amber-400 ring-4 ring-amber-50' : 'border-slate-200'}`}>
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                    {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                    {editingEntryId ? 'Modificar Registro' : 'Nueva Jornada'}
                  </h3>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-bold outline-none focus:ring-4 ring-indigo-50" required />
                    <div className="flex p-1 bg-slate-100 rounded-xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-xs font-black rounded-lg ${entryMode === 'clock' ? 'bg-white shadow-sm' : ''}`}>Reloj</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-xs font-black rounded-lg ${entryMode === 'direct' ? 'bg-white shadow-sm' : ''}`}>Manual</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-2">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 p-4 rounded-2xl font-bold" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 p-4 rounded-2xl font-bold" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-bold" placeholder="hh:mm" />
                    )}
                    <div className="bg-slate-50 p-4 rounded-2xl border flex justify-between items-center">
                      <div><p className="text-[10px] font-black uppercase text-slate-400">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-20 bg-transparent text-xl font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className="text-[10px] font-black uppercase bg-white border px-3 py-1 rounded-full">{formData.isLunchManual ? 'Manual' : 'Auto'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-sm h-24" placeholder="Notas..." />
                    <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-lg">Guardar Cambios</button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4">
                  <h3 className="font-black text-xl">Historial Reciente</h3>
                  <button onClick={handleExportCSV} className="bg-emerald-600 text-white px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2"><Download className="w-4 h-4" /> Exportar</button>
                </div>
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-3xl border shadow-sm group hover:border-indigo-100 transition-all">
                      <div className="flex justify-between items-center mb-4">
                        <span className="font-black text-slate-700">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</span>
                        <div className="flex gap-2">
                          <button onClick={() => handleEditEntry(entry)} className="p-2 text-amber-500 hover:bg-amber-50 rounded-lg"><Edit2 className="w-4 h-4" /></button>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-2 text-center border-y py-4">
                        <div><p className="text-[9px] font-black text-slate-400">NETA</p><p className="font-black text-indigo-600">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400">EXTRA</p><p className="font-black text-emerald-600">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400">DÉFICIT</p><p className="font-black text-rose-500">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[9px] font-black text-slate-400">BRUTA</p><p className="font-bold">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <p className="mt-3 text-xs text-slate-500 italic bg-slate-50 p-2 rounded-lg">{entry.notes}</p>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-3xl border shadow-sm space-y-4">
                  <h3 className="font-black flex items-center gap-2 text-lg"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Compensación</h3>
                  <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-bold">
                    <option value="PAYMENT">Pago Nómina</option>
                    <option value="REST_HOURS">Descanso (Horas)</option>
                    <option value="FREE_DAY">Día Libre (8h)</option>
                  </select>
                  <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-bold" placeholder="hh:mm" />
                  <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-sm h-24" placeholder="Motivo..." />
                  <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl">Aplicar Saldo</button>
                </form>
              </div>
              <div className="lg:col-span-2 overflow-hidden bg-white border rounded-3xl shadow-sm">
                <table className="w-full text-left">
                  <thead className="bg-slate-50">
                    <tr>
                      <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Fecha</th>
                      <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase">Acción</th>
                      <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Cantidad</th>
                      <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase text-right">Borrar</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {workerCompensations.map(c => (
                      <tr key={c.id}>
                        <td className="px-6 py-4 text-sm font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-6 py-4 font-bold text-indigo-600 text-xs">{c.type}</td>
                        <td className="px-6 py-4 text-right font-black">{formatMinutes(c.minutes)}</td>
                        <td className="px-6 py-4 text-right"><button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 p-2"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-3xl border shadow-sm space-y-4">
                  <h3 className="font-black text-lg">Nuevo Miembro</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-bold" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl">Añadir</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-3">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-5 bg-white rounded-3xl border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-md ring-4 ring-indigo-50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black text-lg ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <span className="font-black text-slate-800">{w.name}</span>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-50 text-slate-500'}`}>Seleccionar</button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-3xl border p-8 shadow-sm space-y-4">
              <h3 className="font-black text-xl border-b pb-4">Historial de Auditoría</h3>
              {workerEntries.flatMap(e => e.logs.map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                <div key={log.id} className="p-4 bg-slate-50 rounded-2xl border flex gap-4">
                  <div className="bg-white p-2 rounded-xl border self-start"><History className="w-4 h-4 text-slate-300" /></div>
                  <div className="flex-1 text-sm">
                    <p className="font-bold text-indigo-600">Jornada {log.date} <span className="text-slate-400 text-[10px] font-medium ml-2">{new Date(log.timestamp).toLocaleTimeString()}</span></p>
                    <p className="mt-1">Cambio en <span className="font-black text-slate-700">"{log.field}"</span>: {log.oldValue} → <span className="font-black text-indigo-800">{log.newValue}</span></p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t flex justify-around p-4 md:hidden z-50 shadow-2xl">
        {[ {id:'daily', icon: Calendar, label: 'Jornada'}, {id:'balances', icon: ArrowRightLeft, label: 'Saldo'}, {id:'workers', icon: Users, label: 'Equipo'}, {id:'logs', icon: History, label: 'Logs'} ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1 p-2 rounded-xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 scale-105 shadow-sm' : 'text-slate-400'}`}>
            <t.icon className="w-6 h-6" />
            <span className="text-[8px] font-black uppercase">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

// Generador de ID ultra-seguro para evitar fallos de identificación
const generateId = () => {
  const S4 = () => (((1 + Math.random()) * 0x10000) | 0).toString(16).substring(1);
  return `ID-${S4()}${S4()}-${Date.now()}`;
};

const App: React.FC = () => {
  // --- CARGA INICIAL CON VALIDACIÓN ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    try {
      const saved = localStorage.getItem('tw_workers');
      return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
    } catch { return [{ id: 'W-INITIAL', name: 'Trabajador Principal' }]; }
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_entries');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_compensations');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    const last = localStorage.getItem('tw_last_worker');
    return (last && last !== 'undefined' && last !== 'null') ? last : (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // --- PERSISTENCIA AUTOMÁTICA (SIDE EFFECT) ---
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- DATOS FILTRADOS ---
  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- HANDLERS DE BORRADO (RE-REFACTORIZADOS PARA FUNCIONAR SÍ O SÍ) ---

  const handleDeleteEntry = (idToDelete: string) => {
    if (!window.confirm("¿Confirmas que deseas eliminar permanentemente esta jornada?")) return;

    // 1. Filtrar usando comparación estricta de strings
    const updatedEntries = entries.filter(e => String(e.id).trim() !== String(idToDelete).trim());

    // 2. Actualizar estado de React
    setEntries(updatedEntries);

    // 3. Forzar escritura inmediata en localStorage por si acaso
    localStorage.setItem('tw_entries', JSON.stringify(updatedEntries));

    // 4. Limpiar modo edición si era ese el registro
    if (editingEntryId === idToDelete) setEditingEntryId(null);
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Deseas eliminar esta compensación?")) return;
    const updatedComp = compensations.filter(c => String(c.id).trim() !== String(idToDelete).trim());
    setCompensations(updatedComp);
    localStorage.setItem('tw_compensations', JSON.stringify(updatedComp));
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe existir al menos un trabajador.");
    if (!window.confirm("¿Borrar trabajador? Se perderán todas sus jornadas y saldos.")) return;

    const newWorkers = workers.filter(w => String(w.id) !== String(workerIdToDelete));
    const newEntries = entries.filter(e => String(e.workerId) !== String(workerIdToDelete));
    const newComp = compensations.filter(c => String(c.workerId) !== String(workerIdToDelete));

    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);

    if (selectedWorkerId === workerIdToDelete) {
      setSelectedWorkerId(newWorkers[0].id);
    }
  };

  // --- RESTO DE FUNCIONES ---

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase tracking-widest flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Control Local
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Pagadas / Libres</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensar', icon: ArrowRightLeft },
            { id: 'workers', label: 'Plantilla', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
