}

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { TimeEntry, CompensationEntry, Worker, AuditLog } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

// Generador de ID ultra-seguro para evitar fallos de identificación
const generateId = () => {
  const S4 = () => (((1 + Math.random()) * 0x10000) | 0).toString(16).substring(1);
  return `ID-${S4()}${S4()}-${Date.now()}`;
};

const App: React.FC = () => {
  // --- CARGA INICIAL CON VALIDACIÓN ---
  const [workers, setWorkers] = useState<Worker[]>(() => {
    try {
      const saved = localStorage.getItem('tw_workers');
      return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
    } catch { return [{ id: 'W-INITIAL', name: 'Trabajador Principal' }]; }
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_entries');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    try {
      const saved = localStorage.getItem('tw_compensations');
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    const last = localStorage.getItem('tw_last_worker');
    return (last && last !== 'undefined' && last !== 'null') ? last : (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // --- PERSISTENCIA AUTOMÁTICA (SIDE EFFECT) ---
  useEffect(() => {
    localStorage.setItem('tw_workers', JSON.stringify(workers));
  }, [workers]);

  useEffect(() => {
    localStorage.setItem('tw_entries', JSON.stringify(entries));
  }, [entries]);

  useEffect(() => {
    localStorage.setItem('tw_compensations', JSON.stringify(compensations));
  }, [compensations]);

  useEffect(() => {
    localStorage.setItem('tw_last_worker', selectedWorkerId);
  }, [selectedWorkerId]);

  // Form States
  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    id: null as string | null,
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  // --- DATOS FILTRADOS ---
  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- HANDLERS DE BORRADO ---

  const handleDeleteEntry = (idToDelete: string) => {
    if (!window.confirm("¿Confirmas que deseas eliminar permanentemente esta jornada?")) return;
    const updatedEntries = entries.filter(e => String(e.id).trim() !== String(idToDelete).trim());
    setEntries(updatedEntries);
    if (editingEntryId === idToDelete) setEditingEntryId(null);
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Deseas eliminar esta compensación?")) return;
    const updatedComp = compensations.filter(c => String(c.id).trim() !== String(idToDelete).trim());
    setCompensations(updatedComp);
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe existir al menos un trabajador.");
    if (!window.confirm("¿Borrar trabajador? Se perderán todas sus jornadas y saldos.")) return;

    const newWorkers = workers.filter(w => String(w.id) !== String(workerIdToDelete));
    const newEntries = entries.filter(e => String(e.workerId) !== String(workerIdToDelete));
    const newComp = compensations.filter(c => String(c.workerId) !== String(workerIdToDelete));

    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);

    if (selectedWorkerId === workerIdToDelete) {
      setSelectedWorkerId(newWorkers[0].id);
    }
  };

  // --- HANDLERS DE CREACIÓN/EDICIÓN ---

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // Fix for line 345: handleSaveCompensation
  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("La cantidad debe ser mayor a 0.");

    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };

    setCompensations(prev => [newComp, ...prev]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  // Fix for line 388: handleAddWorker
  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = {
      id: `W-${Date.now()}`,
      name: newWorkerName.trim()
    };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase tracking-widest flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Control Local
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Pagadas / Libres</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensar', icon: ArrowRightLeft },
            { id: 'workers', label: 'Plantilla', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        {/* Content Views */}
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Modificar Registro' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs font-medium h-24" placeholder="Observaciones..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500 shadow-amber-100' : 'bg-indigo-600 shadow-indigo-100'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Jornadas</h3>
                  <button className="text-[10px] font-black uppercase text-indigo-600 flex items-center gap-1"><Download className="w-3 h-3" /> Reporte Completo</button>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic">No hay registros todavía.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
                      <div className="flex justify-between items-start mb-4 relative z-10">
                        <div>
                          <p className="font-black text-slate-800 text-lg">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5">REF: {entry.id}</p>
                        </div>
                        <div className="flex gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => handleEditEntry(entry)} className="p-2 text-amber-500 hover:bg-amber-50 rounded-xl transition-colors"><Edit2 className="w-4 h-4" /></button>
                          <button onClick={() => handleDeleteEntry(entry.id)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition-colors"><Trash2 className="w-4 h-4" /></button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Comida</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.lunchDiscount)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2"><FileText className="w-3 h-3 mt-0.5 flex-shrink-0" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Compensar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm focus:border-indigo-500 outline-none">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24" placeholder="Motivo o concepto..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl active:scale-[0.98]">Efectuar Movimiento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Eliminar</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-2 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right"><button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-2 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No hay compensaciones registradas.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Empleado</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl shadow-indigo-100 active:scale-[0.98]">Añadir Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800">{w.name}</p>
                        <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b">Auditoría de Sesión</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-4 h-4" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-1.5">
                        <p className="font-black text-indigo-600 uppercase">Jornada {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleTimeString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed">Campo <span className="text-slate-900 font-black">"{log.field}"</span> modificado de <span className="text-slate-400 line-through">"{log.oldValue}"</span> a <span className="text-slate-900 font-black">"{log.newValue}"</span>.</p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">Sin datos de auditoría.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Mobile Bar */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.05)]">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Plantilla'}, 
          {id:'logs', icon: History, label: 'Auditoría'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-4 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Persistencia de efectos
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // FUNCIONES DE BORRADO CRÍTICAS (CORREGIDAS)
  const handleDeleteEntry = (idToDelete: string) => {
    if (!window.confirm("¿Estás seguro de que deseas eliminar este registro de jornada? Esta acción no se puede deshacer.")) return;

    // Usamos el ID limpio para filtrar
    const cleanedId = String(idToDelete).trim();
    const updatedEntries = entries.filter(e => String(e.id).trim() !== cleanedId);

    // Actualización atómica de estado y almacenamiento
    setEntries(updatedEntries);
    localStorage.setItem('tw_entries', JSON.stringify(updatedEntries));

    if (editingEntryId === idToDelete) {
      setEditingEntryId(null);
    }
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Eliminar este registro de compensación?")) return;

    const cleanedId = String(idToDelete).trim();
    const updatedComp = compensations.filter(c => String(c.id).trim() !== cleanedId);

    setCompensations(updatedComp);
    localStorage.setItem('tw_compensations', JSON.stringify(updatedComp));
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe existir al menos un perfil de trabajador.");
    if (!window.confirm("¿Borrar trabajador? Se eliminarán permanentemente todas sus jornadas y saldos.")) return;

    const newWorkers = workers.filter(w => String(w.id) !== String(workerIdToDelete));
    const newEntries = entries.filter(e => String(e.workerId) !== String(workerIdToDelete));
    const newComp = compensations.filter(c => String(c.workerId) !== String(workerIdToDelete));

    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);

    if (selectedWorkerId === workerIdToDelete) {
      setSelectedWorkerId(newWorkers[0].id);
    }
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Introduce una cantidad válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(prev => [newComp, ...prev]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Almacenamiento Local Activo
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Pagadas / Libres</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensar', icon: ArrowRightLeft },
            { id: 'workers', label: 'Plantilla', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Modificar Registro' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24" placeholder="Observaciones..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all ${editingEntryId ? 'bg-amber-500' : 'bg-indigo-600'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Jornadas</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic">No hay registros todavía.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group overflow-hidden">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5">REF: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            onClick={() => handleEditEntry(entry)} 
                            className="p-2.5 text-amber-500 hover:bg-amber-50 rounded-xl transition-colors"
                            title="Editar registro"
                          >
                            <Edit2 className="w-4 h-4" />
                          </button>
                          <button 
                            onClick={() => handleDeleteEntry(entry.id)} 
                            className="p-2.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-colors"
                            title="Eliminar registro"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2"><FileText className="w-3 h-3 mt-0.5" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Compensar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24" placeholder="Concepto..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl">Aplicar Movimiento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-2 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-2 rounded-xl transition-all">
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No hay compensaciones registradas.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Empleado</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl shadow-indigo-100">Añadir Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div><p className="font-black text-slate-800">{w.name}</p></div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b">Auditoría de Sesión</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-4 h-4" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-1.5">
                        <p className="font-black text-indigo-600 uppercase">Jornada {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleTimeString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed">Cambio en <span className="text-slate-900 font-black">"{log.field}"</span>: {log.oldValue} → <span className="text-slate-900 font-black">"{log.newValue}"</span>.</p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">Sin datos de auditoría.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-2xl">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Plantilla'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-4 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sincronización automática básica
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- LÓGICA DE BORRADO ATÓMICA Y DEFINITIVA ---

  const handleDeleteEntry = (idToDelete: string) => {
    if (!window.confirm("¿Confirmas que deseas eliminar esta jornada permanentemente?")) return;

    // 1. Filtrar los datos
    const updated = entries.filter(e => String(e.id) !== String(idToDelete));

    // 2. Actualizar estado e inmediatamente localStorage para evitar restauraciones por useEffect
    setEntries(updated);
    localStorage.setItem('tw_entries', JSON.stringify(updated));

    // 3. Limpiar edición si es necesario
    if (editingEntryId === idToDelete) setEditingEntryId(null);
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Eliminar esta compensación?")) return;

    const updated = compensations.filter(c => String(c.id) !== String(idToDelete));
    setCompensations(updated);
    localStorage.setItem('tw_compensations', JSON.stringify(updated));
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("No puedes eliminar al único trabajador.");
    if (!window.confirm("¿Borrar trabajador y todos sus registros asociados?")) return;

    const newWorkers = workers.filter(w => String(w.id) !== String(workerIdToDelete));
    const newEntries = entries.filter(e => String(e.workerId) !== String(workerIdToDelete));
    const newComp = compensations.filter(c => String(c.workerId) !== String(workerIdToDelete));

    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);

    localStorage.setItem('tw_workers', JSON.stringify(newWorkers));
    localStorage.setItem('tw_entries', JSON.stringify(newEntries));
    localStorage.setItem('tw_compensations', JSON.stringify(newComp));

    if (selectedWorkerId === workerIdToDelete) {
      setSelectedWorkerId(newWorkers[0].id);
    }
  };

  // --- HANDLERS DE CREACIÓN ---

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        ent.id === editingEntryId 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Introduce una cantidad válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(prev => [newComp, ...prev]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Persistencia Activa
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard Resumen */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Compensado</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Navegación Pestañas */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Bolsa', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        {/* Contenido Principal */}
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Editar Jornada' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24" placeholder="Observaciones..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500' : 'bg-indigo-600'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial Reciente</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic shadow-sm">No hay jornadas registradas.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5">REFERENCIA: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            onClick={() => handleEditEntry(entry)} 
                            className="p-3 text-amber-500 hover:bg-amber-50 rounded-xl transition-all"
                            title="Editar"
                          >
                            <Edit2 className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => handleDeleteEntry(entry.id)} 
                            className="p-3 text-rose-500 hover:bg-rose-100 rounded-xl transition-all"
                            title="Borrar Definitivamente"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100"><FileText className="w-4 h-4 text-slate-300" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Liquidar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none focus:border-indigo-500">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24" placeholder="Nota aclaratoria..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 active:scale-[0.98] transition-all">Efectuar Descuento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Monto</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-3 rounded-xl transition-all">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">Historial de bolsa vacío.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Perfil</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">Crear Registro</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b">Auditoría de Cambios</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start transition-all hover:bg-slate-100/50">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-5 h-5" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-2">
                        <p className="font-black text-indigo-600 uppercase tracking-tight text-[11px]">Jornada del {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed text-[13px]">
                        Se ha modificado el campo <span className="text-slate-900 font-black">"{log.field}"</span>. 
                        Valor anterior: <span className="text-slate-400 line-through">"{log.oldValue}"</span> → Nuevo valor: <span className="text-slate-900 font-black">"{log.newValue}"</span>.
                      </p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">No hay registros de auditoría para este trabajador.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Menú Móvil Inferior */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-5 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 shadow-inner' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- LÓGICA DE BORRADO 100% EFECTIVA ---

  const handleDeleteEntry = (idToDelete: string) => {
    if (!window.confirm("¿Estás seguro? Esta jornada se eliminará permanentemente del sistema.")) return;

    // 1. Filtrar usando comparación estricta de string
    const updatedEntries = entries.filter(e => String(e.id) !== String(idToDelete));

    // 2. Actualizar estado de React
    setEntries(updatedEntries);

    // 3. Forzar persistencia inmediata para evitar que el useEffect falle
    localStorage.setItem('tw_entries', JSON.stringify(updatedEntries));

    // 4. Si estábamos editando este registro, cancelar edición
    if (editingEntryId === idToDelete) setEditingEntryId(null);
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Deseas eliminar este registro de compensación? El saldo se actualizará automáticamente.")) return;

    const updatedCompensations = compensations.filter(c => String(c.id) !== String(idToDelete));
    setCompensations(updatedCompensations);
    localStorage.setItem('tw_compensations', JSON.stringify(updatedCompensations));
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("El sistema requiere al menos un trabajador activo.");
    if (!window.confirm("¡ATENCIÓN! Se borrarán todos los datos, jornadas y horas extra de este trabajador. ¿Continuar?")) return;

    const newWorkers = workers.filter(w => String(w.id) !== String(workerIdToDelete));
    const newEntries = entries.filter(e => String(e.workerId) !== String(workerIdToDelete));
    const newComp = compensations.filter(c => String(c.workerId) !== String(workerIdToDelete));

    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);

    localStorage.setItem('tw_workers', JSON.stringify(newWorkers));
    localStorage.setItem('tw_entries', JSON.stringify(newEntries));
    localStorage.setItem('tw_compensations', JSON.stringify(newComp));

    if (selectedWorkerId === workerIdToDelete) {
      setSelectedWorkerId(newWorkers[0].id);
    }
  };

  // --- HANDLERS DE CREACIÓN Y EDICIÓN ---

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(prev => prev.map(ent => 
        String(ent.id) === String(editingEntryId) 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      ));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("La cantidad debe ser superior a cero.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(prev => [newComp, ...prev]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(prev => [...prev, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema Sincronizado
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard Resumen */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Liquidado</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Pestañas */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Compensar', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Historial', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Modificar Jornada' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24" placeholder="Observaciones..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500' : 'bg-indigo-600'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Jornadas</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic shadow-sm">No hay jornadas registradas.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5">ID: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            onClick={() => handleEditEntry(entry)} 
                            className="p-3 text-amber-500 hover:bg-amber-50 rounded-xl transition-all"
                            title="Editar"
                          >
                            <Edit2 className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => handleDeleteEntry(entry.id)} 
                            className="p-3 text-rose-500 hover:bg-rose-100 rounded-xl transition-all"
                            title="Borrar Registro"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100"><FileText className="w-4 h-4 text-slate-300" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Liquidar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none focus:border-indigo-500">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24" placeholder="Motivo de la compensación..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 transition-all">Efectuar Descuento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-3 rounded-xl transition-all">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No hay compensaciones en el historial.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Trabajador</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all">Añadir al Equipo</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b">Auditoría de Cambios</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start transition-all hover:bg-slate-100/50">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-5 h-5" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-2">
                        <p className="font-black text-indigo-600 uppercase tracking-tight text-[11px]">Jornada del {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed text-[13px]">
                        Se ha modificado el registro. Cambio en <span className="text-slate-900 font-black">"{log.field}"</span> de <span className="text-slate-400 line-through">"{log.oldValue}"</span> a <span className="text-slate-900 font-black">"{log.newValue}"</span>.
                      </p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">Sin datos de auditoría disponibles.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Menú Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-2xl">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Historial'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-5 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 shadow-inner' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sincronización automática de cambios de estado a localStorage (Respaldado por borrado imperativo)
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- LÓGICA DE BORRADO DEFINITIVA (CORREGIDA) ---

  const handleDeleteEntry = (idToDelete: string) => {
    const confirmDelete = window.confirm("¿Confirmas que deseas eliminar esta jornada permanentemente? Esta acción es irreversible.");
    if (!confirmDelete) return;

    // Obtenemos el ID unívoco en formato string
    const targetId = String(idToDelete);

    // Creamos la nueva lista filtrada
    const remainingEntries = entries.filter(e => String(e.id) !== targetId);

    // 1. Actualizamos el estado de React inmediatamente
    setEntries(remainingEntries);

    // 2. FORZAMOS el guardado en LocalStorage en este mismo instante
    // Esto evita que los efectos secundarios o recargas recuperen el dato
    localStorage.setItem('tw_entries', JSON.stringify(remainingEntries));

    // 3. Limpieza de estado de edición si el borrado coincide
    if (editingEntryId === idToDelete) {
      setEditingEntryId(null);
    }
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Eliminar este registro de compensación?")) return;

    const targetId = String(idToDelete);
    const remainingCompensations = compensations.filter(c => String(c.id) !== targetId);

    setCompensations(remainingCompensations);
    localStorage.setItem('tw_compensations', JSON.stringify(remainingCompensations));
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe haber al menos un trabajador en el sistema.");
    if (!window.confirm("Se borrarán todos los datos del trabajador. ¿Continuar?")) return;

    const targetWorkerId = String(workerIdToDelete);
    const newWorkers = workers.filter(w => String(w.id) !== targetWorkerId);
    const newEntries = entries.filter(e => String(e.workerId) !== targetWorkerId);
    const newComp = compensations.filter(c => String(c.workerId) !== targetWorkerId);

    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);

    localStorage.setItem('tw_workers', JSON.stringify(newWorkers));
    localStorage.setItem('tw_entries', JSON.stringify(newEntries));
    localStorage.setItem('tw_compensations', JSON.stringify(newComp));

    if (String(selectedWorkerId) === targetWorkerId) {
      setSelectedWorkerId(newWorkers[0].id);
    }
  };

  // --- HANDLERS DE CREACIÓN Y EDICIÓN ---

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      const updated = entries.map(ent => 
        String(ent.id) === String(editingEntryId) 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      );
      setEntries(updated);
      localStorage.setItem('tw_entries', JSON.stringify(updated));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      const newEntriesList = [newEntry, ...entries];
      setEntries(newEntriesList);
      localStorage.setItem('tw_entries', JSON.stringify(newEntriesList));
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad inválida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    const newList = [newComp, ...compensations];
    setCompensations(newList);
    localStorage.setItem('tw_compensations', JSON.stringify(newList));
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    const newList = [...workers, newWorker];
    setWorkers(newList);
    localStorage.setItem('tw_workers', JSON.stringify(newList));
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Almacenamiento Local Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard Resumen */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Compensado</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500 transition-transform hover:scale-[1.02]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Pestañas de Navegación */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Bolsa', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Historial', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        {/* Contenido Pestaña Jornadas */}
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Modificar Registro' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24" placeholder="Observaciones..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500' : 'bg-indigo-600'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Actividad</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic shadow-sm">No hay registros guardados.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5">REF: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            onClick={() => handleEditEntry(entry)} 
                            className="p-3 text-amber-500 hover:bg-amber-50 rounded-xl transition-all active:scale-90"
                            title="Editar registro"
                          >
                            <Edit2 className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => handleDeleteEntry(entry.id)} 
                            className="p-3 text-rose-500 hover:bg-rose-100 rounded-xl transition-all active:scale-90"
                            title="Borrar registro permanentemente"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100"><FileText className="w-4 h-4 text-slate-300" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Liquidar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none focus:border-indigo-500">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24" placeholder="Nota de seguimiento..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 transition-all">Descontar de Bolsa</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Monto</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-3 rounded-xl transition-all">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">Historial de bolsa libre de deudas.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Añadir Operario</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all">Crear Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b">Registro de Auditoría</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start transition-all hover:bg-slate-100/50">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-5 h-5" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-2">
                        <p className="font-black text-indigo-600 uppercase tracking-tight text-[11px]">Día {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed text-[13px]">
                        Actualización de <span className="text-slate-900 font-black">"{log.field}"</span>. 
                        Antiguo: <span className="text-slate-400 line-through">"{log.oldValue}"</span> → Nuevo: <span className="text-slate-900 font-black">"{log.newValue}"</span>.
                      </p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">No se han registrado cambios recientes para auditar.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Navegación Inferior Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-5 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 shadow-inner' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- MÉTODO CRUD: ELIMINAR JORNADA (100% EFECTIVO) ---
  const handleDeleteEntry = (idToDelete: string) => {
    // 1. Confirmación de seguridad
    if (!window.confirm("¿Seguro que quieres borrar este registro? Los datos de horas extra asociados se perderán.")) return;

    // 2. Identificamos el registro de forma segura
    const targetId = String(idToDelete);

    // 3. Generamos la nueva lista sin el elemento
    const updatedEntries = entries.filter(e => String(e.id) !== targetId);

    // 4. Actualizamos el ESTADO (Memoria RAM)
    setEntries(updatedEntries);

    // 5. Actualizamos el STORAGE (Disco Duro) inmediatamente
    // Esto garantiza que aunque se refresque la página, el dato ya no exista
    localStorage.setItem('tw_entries', JSON.stringify(updatedEntries));

    // 6. Si el elemento borrado se estaba editando, limpiamos el formulario
    if (editingEntryId === targetId) {
      setEditingEntryId(null);
      setFormData(prev => ({...prev, notes: ''}));
    }
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Eliminar este registro de compensación?")) return;
    const targetId = String(idToDelete);
    const updatedComp = compensations.filter(c => String(c.id) !== targetId);
    setCompensations(updatedComp);
    localStorage.setItem('tw_compensations', JSON.stringify(updatedComp));
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe haber al menos un trabajador.");
    if (!window.confirm("Se borrarán todos los datos del trabajador. ¿Continuar?")) return;
    const targetId = String(workerIdToDelete);
    const newWorkers = workers.filter(w => String(w.id) !== targetId);
    const newEntries = entries.filter(e => String(e.workerId) !== targetId);
    const newComp = compensations.filter(c => String(c.workerId) !== targetId);
    setWorkers(newWorkers);
    setEntries(newEntries);
    setCompensations(newComp);
    localStorage.setItem('tw_workers', JSON.stringify(newWorkers));
    localStorage.setItem('tw_entries', JSON.stringify(newEntries));
    localStorage.setItem('tw_compensations', JSON.stringify(newComp));
    if (String(selectedWorkerId) === targetId) setSelectedWorkerId(newWorkers[0].id);
  };

  // --- MÉTODOS CRUD: CREAR Y ACTUALIZAR ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      const updated = entries.map(ent => 
        String(ent.id) === String(editingEntryId) 
          ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
          : ent
      );
      setEntries(updated);
      localStorage.setItem('tw_entries', JSON.stringify(updated));
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      const newEntriesList = [newEntry, ...entries];
      setEntries(newEntriesList);
      localStorage.setItem('tw_entries', JSON.stringify(newEntriesList));
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad inválida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    const newList = [newComp, ...compensations];
    setCompensations(newList);
    localStorage.setItem('tw_compensations', JSON.stringify(newList));
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    const newList = [...workers, newWorker];
    setWorkers(newList);
    localStorage.setItem('tw_workers', JSON.stringify(newList));
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Almacenamiento Local Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

