                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24 focus:border-indigo-500 outline-none resize-none" placeholder="Nota aclaratoria..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 transition-all active:scale-[0.98]">Efectuar Descuento</button>
