          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Operario</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all active:scale-[0.98]">Añadir Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest font-mono">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all active:scale-90"><Trash2 className="w-5 h-5" /></button>
