import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- MÉTODO CRUD: ELIMINAR JORNADA ---
  const handleDeleteEntry = (idToDelete: string) => {
    // Paso 1: Confirmación
    if (!window.confirm("¿Confirmar eliminación definitiva del registro?")) return;

    const targetId = String(idToDelete);

    // Paso 2: Actualización FUNCIONAL del estado
    // Esto asegura que usamos la versión más reciente de 'entries'
    setEntries(currentEntries => {
      const updatedEntries = currentEntries.filter(e => String(e.id) !== targetId);

      // Paso 3: Persistencia inmediata dentro del callback para evitar condiciones de carrera
      localStorage.setItem('tw_entries', JSON.stringify(updatedEntries));

      return updatedEntries;
    });

    // Paso 4: Limpieza de UI si se estaba editando
    if (editingEntryId === targetId) {
      setEditingEntryId(null);
      setFormData({
        date: new Date().toISOString().split('T')[0],
        startTime: '08:00',
        endTime: '17:00',
        hours: '08:00',
        lunch: '01:00',
        isLunchManual: false,
        notes: ''
      });
    }
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Eliminar este registro de compensación?")) return;
    const targetId = String(idToDelete);
    setCompensations(current => {
      const updated = current.filter(c => String(c.id) !== targetId);
      localStorage.setItem('tw_compensations', JSON.stringify(updated));
      return updated;
    });
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe haber al menos un trabajador en el sistema.");
    if (!window.confirm("Se borrarán todos los datos del trabajador. ¿Continuar?")) return;
    const targetId = String(workerIdToDelete);

    setWorkers(prev => {
      const newWorkers = prev.filter(w => String(w.id) !== targetId);
      localStorage.setItem('tw_workers', JSON.stringify(newWorkers));
      if (String(selectedWorkerId) === targetId) setSelectedWorkerId(newWorkers[0].id);
      return newWorkers;
    });

    setEntries(prev => {
      const newEntries = prev.filter(e => String(e.workerId) !== targetId);
      localStorage.setItem('tw_entries', JSON.stringify(newEntries));
      return newEntries;
    });

    setCompensations(prev => {
      const newComp = prev.filter(c => String(c.workerId) !== targetId);
      localStorage.setItem('tw_compensations', JSON.stringify(newComp));
      return newComp;
    });
  };

  // --- HANDLERS CREAR/EDITAR ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(current => {
        const updated = current.map(ent => 
          String(ent.id) === String(editingEntryId) 
            ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
            : ent
        );
        localStorage.setItem('tw_entries', JSON.stringify(updated));
        return updated;
      });
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(current => {
        const newList = [newEntry, ...current];
        localStorage.setItem('tw_entries', JSON.stringify(newList));
        return newList;
      });
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad no válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(current => {
      const newList = [newComp, ...current];
      localStorage.setItem('tw_compensations', JSON.stringify(newList));
      return newList;
    });
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(current => {
      const newList = [...current, newWorker];
      localStorage.setItem('tw_workers', JSON.stringify(newList));
      return newList;
    });
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Registro Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
