import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  Download
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- MÉTODO CRUD: ELIMINAR JORNADA ---
  const handleDeleteEntry = (idToDelete: string) => {
    console.log("Iniciando proceso de eliminación para:", idToDelete);

    if (!window.confirm("¿Confirmar eliminación definitiva del registro?")) {
      console.log("Eliminación cancelada por el usuario");
      return;
    }

    // Actualización PURA del estado (sin side-effects como localStorage dentro)
    // El useEffect se encargará de guardar los cambios
    setEntries(prev => {
      const filtered = prev.filter(e => e.id !== idToDelete);
      console.log(`Estado actualizado. De ${prev.length} a ${filtered.length} entradas.`);
      return filtered;
    });

    // Limpieza de formulario si es necesario
    if (editingEntryId === idToDelete) {
      setEditingEntryId(null);
      setFormData({
        date: new Date().toISOString().split('T')[0],
        startTime: '08:00',
        endTime: '17:00',
        hours: '08:00',
        lunch: '01:00',
        isLunchManual: false,
        notes: ''
      });
    }
  };

  const handleDeleteComp = (idToDelete: string) => {
    if (!window.confirm("¿Eliminar este registro de compensación?")) return;
    const targetId = String(idToDelete);
    setCompensations(current => {
      const updated = current.filter(c => String(c.id) !== targetId);
      return updated;
    });
  };

  const handleDeleteWorker = (workerIdToDelete: string) => {
    if (workers.length <= 1) return alert("Debe haber al menos un trabajador en el sistema.");
    if (!window.confirm("Se borrarán todos los datos del trabajador. ¿Continuar?")) return;
    const targetId = String(workerIdToDelete);

    setWorkers(prev => {
      const newWorkers = prev.filter(w => String(w.id) !== targetId);
      if (String(selectedWorkerId) === targetId) setSelectedWorkerId(newWorkers[0].id);
      return newWorkers;
    });

    setEntries(prev => prev.filter(e => String(e.workerId) !== targetId));
    setCompensations(prev => prev.filter(c => String(c.workerId) !== targetId));
  };

  // --- HANDLERS CREAR/EDITAR ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(current => {
        const updated = current.map(ent => 
          String(ent.id) === String(editingEntryId) 
            ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
            : ent
        );
        return updated;
      });
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(current => [newEntry, ...current]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad no válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(current => [newComp, ...current]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(current => [...current, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Registro Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Compensado</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Pestañas */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Bolsa', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Editar Jornada' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl transition-all ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl transition-all ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 transition-all ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24 focus:border-indigo-500 outline-none resize-none" placeholder="Notas de la jornada..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500 hover:bg-amber-600 shadow-amber-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Jornadas</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic shadow-sm">No hay registros para este trabajador.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5 font-mono">ID: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handleEditEntry(entry);
                            }} 
                            className="p-3 text-amber-500 hover:bg-amber-50 rounded-xl transition-all active:scale-90 relative z-10 cursor-pointer"
                            title="Editar"
                            aria-label="Editar registro"
                          >
                            <Edit2 className="w-5 h-5 pointer-events-none" />
                          </button>
                          <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              console.log("Click en eliminar", entry.id);
                              handleDeleteEntry(entry.id);
                            }} 
                            className="p-3 text-rose-500 hover:bg-rose-100 rounded-xl transition-all active:scale-90 relative z-10 cursor-pointer"
                            title="Eliminar registro"
                            aria-label="Eliminar registro"
                          >
                            <Trash2 className="w-5 h-5 pointer-events-none" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100"><FileText className="w-4 h-4 text-slate-300" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2 text-lg"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Compensar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none focus:border-indigo-500">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24 focus:border-indigo-500 outline-none resize-none" placeholder="Anotación..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 transition-all active:scale-[0.98]">Aplicar Descuento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-3 rounded-xl transition-all active:scale-90">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No hay compensaciones registradas.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Trabajador</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all active:scale-[0.98]">Añadir Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest font-mono">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all active:scale-90"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b flex items-center gap-2 text-indigo-600"><History className="w-6 h-6" /> Auditoría de Cambios</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start transition-all hover:bg-slate-100/50">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-5 h-5" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-2">
                        <p className="font-black text-indigo-600 uppercase tracking-tight text-[11px]">Jornada: {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed text-[13px]">
                        Campo <span className="text-slate-900 font-black">"{log.field}"</span> modificado. 
                        Valor anterior: <span className="text-slate-400 line-through">"{log.oldValue}"</span> → Nuevo valor: <span className="text-slate-900 font-black">"{log.newValue}"</span>.
                      </p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">Sin registros de auditoría para este perfil.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Menú Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-2xl">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-5 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 shadow-inner' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  AlertTriangle
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Estado para el modal de confirmación
  const [deleteConfirmation, setDeleteConfirmation] = useState<{
    id: string;
    type: 'ENTRY' | 'COMPENSATION' | 'WORKER';
    title: string;
    message: string;
  } | null>(null);

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- SOLICITUDES DE BORRADO (ABREN MODAL) ---
  const handleDeleteEntry = (id: string) => {
    setDeleteConfirmation({
      id,
      type: 'ENTRY',
      title: '¿Eliminar Jornada?',
      message: 'Esta acción eliminará el registro de horas permanentemente. No se puede deshacer.'
    });
  };

  const handleDeleteComp = (id: string) => {
    setDeleteConfirmation({
      id,
      type: 'COMPENSATION',
      title: '¿Eliminar Compensación?',
      message: 'Se eliminará este registro de la bolsa de horas.'
    });
  };

  const handleDeleteWorker = (id: string) => {
    if (workers.length <= 1) {
      alert("Debe haber al menos un trabajador en el sistema.");
      return;
    }
    setDeleteConfirmation({
      id,
      type: 'WORKER',
      title: '¿Eliminar Trabajador?',
      message: '¡Atención! Se borrarán TODAS las jornadas y compensaciones asociadas a este perfil. Esta acción es destructiva.'
    });
  };

  // --- EJECUCIÓN DE BORRADO ---
  const executeDelete = () => {
    if (!deleteConfirmation) return;
    const { id, type } = deleteConfirmation;

    if (type === 'ENTRY') {
      setEntries(prev => prev.filter(e => e.id !== id));
      if (editingEntryId === id) {
        setEditingEntryId(null);
        setFormData({
          date: new Date().toISOString().split('T')[0],
          startTime: '08:00', endTime: '17:00', hours: '08:00',
          lunch: '01:00', isLunchManual: false, notes: ''
        });
      }
    } else if (type === 'COMPENSATION') {
      setCompensations(prev => prev.filter(c => c.id !== id));
    } else if (type === 'WORKER') {
      setWorkers(prev => {
        const newWorkers = prev.filter(w => w.id !== id);
        // Si borramos el seleccionado, cambiamos al primero disponible
        if (selectedWorkerId === id) setSelectedWorkerId(newWorkers[0].id);
        return newWorkers;
      });
      // Limpieza en cascada
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
    }

    setDeleteConfirmation(null);
  };

  // --- HANDLERS CREAR/EDITAR ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(current => {
        const updated = current.map(ent => 
          String(ent.id) === String(editingEntryId) 
            ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
            : ent
        );
        return updated;
      });
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(current => [newEntry, ...current]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad no válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(current => [newComp, ...current]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(current => [...current, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Registro Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-indigo-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-indigo-600 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Compensado</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Pestañas */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Bolsa', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-indigo-600" />}
                      {editingEntryId ? 'Editar Jornada' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-indigo-500 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl transition-all ${entryMode === 'clock' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl transition-all ${entryMode === 'direct' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-indigo-600" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 transition-all ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24 focus:border-indigo-500 outline-none resize-none" placeholder="Notas de la jornada..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500 hover:bg-amber-600 shadow-amber-100' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Jornadas</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic shadow-sm">No hay registros para este trabajador.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5 font-mono">ID: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handleEditEntry(entry);
                            }} 
                            className="p-3 text-amber-500 hover:bg-amber-50 rounded-xl transition-all active:scale-90 relative z-10 cursor-pointer"
                            title="Editar"
                            aria-label="Editar registro"
                          >
                            <Edit2 className="w-5 h-5 pointer-events-none" />
                          </button>
                          <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handleDeleteEntry(entry.id);
                            }} 
                            className="p-3 text-rose-500 hover:bg-rose-100 rounded-xl transition-all active:scale-90 relative z-10 cursor-pointer"
                            title="Eliminar registro"
                            aria-label="Eliminar registro"
                          >
                            <Trash2 className="w-5 h-5 pointer-events-none" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-indigo-600 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100"><FileText className="w-4 h-4 text-slate-300" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2 text-lg"><ArrowRightLeft className="w-5 h-5 text-indigo-600" /> Compensar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none focus:border-indigo-500">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black focus:border-indigo-500 outline-none" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24 focus:border-indigo-500 outline-none resize-none" placeholder="Anotación..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 transition-all active:scale-[0.98]">Aplicar Descuento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-3 rounded-xl transition-all active:scale-90">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No hay compensaciones registradas.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-indigo-600" /> Nuevo Trabajador</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-indigo-500" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all active:scale-[0.98]">Añadir Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-indigo-600 shadow-lg shadow-indigo-50 ring-4 ring-indigo-50/50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest font-mono">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-indigo-50 text-indigo-700' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all active:scale-90"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b flex items-center gap-2 text-indigo-600"><History className="w-6 h-6" /> Auditoría de Cambios</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start transition-all hover:bg-slate-100/50">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-5 h-5" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-2">
                        <p className="font-black text-indigo-600 uppercase tracking-tight text-[11px]">Jornada: {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed text-[13px]">
                        Campo <span className="text-slate-900 font-black">"{log.field}"</span> modificado. 
                        Valor anterior: <span className="text-slate-400 line-through">"{log.oldValue}"</span> → Nuevo valor: <span className="text-slate-900 font-black">"{log.newValue}"</span>.
                      </p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">Sin registros de auditoría para este perfil.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Menú Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-2xl">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-5 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-indigo-600 bg-indigo-50 shadow-inner' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>

      {/* Modal de Confirmación */}
      {deleteConfirmation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-[2rem] p-8 max-w-sm w-full shadow-2xl border-2 border-white scale-100 animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-rose-50 rounded-full flex items-center justify-center mb-6 mx-auto border-4 border-rose-100">
              <Trash2 className="w-8 h-8 text-rose-500" />
            </div>
            <h3 className="text-xl font-black text-slate-800 text-center mb-3 leading-tight">
              {deleteConfirmation.title}
            </h3>
            <p className="text-slate-500 text-center text-xs font-medium leading-relaxed mb-8 px-2">
              {deleteConfirmation.message}
            </p>
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setDeleteConfirmation(null)}
                className="py-4 px-4 rounded-2xl font-black text-xs uppercase tracking-wider text-slate-500 hover:bg-slate-50 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={executeDelete}
                className="py-4 px-4 rounded-2xl font-black text-xs uppercase tracking-wider text-white bg-rose-500 hover:bg-rose-600 shadow-xl shadow-rose-200 transition-all active:scale-95"
              >
                Sí, Eliminar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  AlertTriangle
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Estado para el modal de confirmación
  const [deleteConfirmation, setDeleteConfirmation] = useState<{
    id: string;
    type: 'ENTRY' | 'COMPENSATION' | 'WORKER';
    title: string;
    message: string;
  } | null>(null);

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- SOLICITUDES DE BORRADO (ABREN MODAL) ---
  const handleDeleteEntry = (id: string) => {
    setDeleteConfirmation({
      id,
      type: 'ENTRY',
      title: '¿Eliminar Jornada?',
      message: 'Esta acción eliminará el registro de horas permanentemente. No se puede deshacer.'
    });
  };

  const handleDeleteComp = (id: string) => {
    setDeleteConfirmation({
      id,
      type: 'COMPENSATION',
      title: '¿Eliminar Compensación?',
      message: 'Se eliminará este registro de la bolsa de horas.'
    });
  };

  const handleDeleteWorker = (id: string) => {
    if (workers.length <= 1) {
      alert("Debe haber al menos un trabajador en el sistema.");
      return;
    }
    setDeleteConfirmation({
      id,
      type: 'WORKER',
      title: '¿Eliminar Trabajador?',
      message: '¡Atención! Se borrarán TODAS las jornadas y compensaciones asociadas a este perfil. Esta acción es destructiva.'
    });
  };

  // --- EJECUCIÓN DE BORRADO ---
  const executeDelete = () => {
    if (!deleteConfirmation) return;
    const { id, type } = deleteConfirmation;

    if (type === 'ENTRY') {
      setEntries(prev => prev.filter(e => e.id !== id));
      if (editingEntryId === id) {
        setEditingEntryId(null);
        setFormData({
          date: new Date().toISOString().split('T')[0],
          startTime: '08:00', endTime: '17:00', hours: '08:00',
          lunch: '01:00', isLunchManual: false, notes: ''
        });
      }
    } else if (type === 'COMPENSATION') {
      setCompensations(prev => prev.filter(c => c.id !== id));
    } else if (type === 'WORKER') {
      setWorkers(prev => {
        const newWorkers = prev.filter(w => w.id !== id);
        // Si borramos el seleccionado, cambiamos al primero disponible
        if (selectedWorkerId === id) setSelectedWorkerId(newWorkers[0].id);
        return newWorkers;
      });
      // Limpieza en cascada
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
    }

    setDeleteConfirmation(null);
  };

  // --- HANDLERS CREAR/EDITAR ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    let brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
      (() => {
        const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
        return f >= s ? f - s : (1440 - s) + f;
      })();
    let lunch = parseHHMM(formData.lunch);
    if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;

    if (editingEntryId) {
      setEntries(current => {
        const updated = current.map(ent => 
          String(ent.id) === String(editingEntryId) 
            ? { ...ent, date: formData.date, hoursBrutas: brutas, lunchDiscount: lunch, notes: formData.notes }
            : ent
        );
        return updated;
      });
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        notes: formData.notes,
        logs: []
      };
      setEntries(current => [newEntry, ...current]);
    }
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      notes: entry.notes || ''
    });
    setEntryMode('direct');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad no válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(current => [newComp, ...current]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(current => [...current, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-blue-900 p-2 rounded-xl shadow-lg shadow-blue-200"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Registro Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-blue-800 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Bolsa Horas Extra</p>
            <span className="text-3xl font-black text-blue-900 tracking-tighter">{formatMinutes(totals.pending)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-rose-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Déficit Acumulado</p>
            <span className="text-3xl font-black text-rose-500 tracking-tighter">{formatMinutes(totals.deficit)}</span>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-emerald-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Compensado</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-black text-emerald-600">{formatMinutes(totals.paid)}</span>
              <span className="text-xl font-black text-blue-500">/ {formatMinutes(totals.rested)}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm border-b-4 border-b-amber-500 transition-all hover:translate-y-[-2px]">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Días Libres</p>
            <span className="text-3xl font-black text-slate-800 tracking-tighter">{totals.days}</span>
          </div>
        </div>

        {/* Pestañas */}
        <div className="flex bg-white rounded-3xl border border-slate-200 p-1 shadow-sm max-w-fit overflow-x-auto no-scrollbar">
          {[
            { id: 'daily', label: 'Jornadas', icon: Calendar },
            { id: 'balances', label: 'Bolsa', icon: ArrowRightLeft },
            { id: 'workers', label: 'Equipo', icon: Users },
            { id: 'logs', label: 'Auditoría', icon: History }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold text-xs transition-all ${activeTab === tab.id ? 'bg-blue-900 text-white shadow-lg shadow-blue-200' : 'text-slate-500 hover:bg-slate-50'}`}>
              <tab.icon className="w-4 h-4" /> {tab.label}
            </button>
          ))}
        </div>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          {activeTab === 'daily' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddEntry} className={`bg-white p-8 rounded-[2.5rem] border-2 shadow-sm space-y-6 transition-all ${editingEntryId ? 'border-amber-400 bg-amber-50/20' : 'border-slate-100'}`}>
                  <div className="flex justify-between items-center">
                    <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg">
                      {editingEntryId ? <Edit2 className="w-5 h-5 text-amber-500" /> : <Plus className="w-5 h-5 text-blue-900" />}
                      {editingEntryId ? 'Editar Jornada' : 'Nueva Jornada'}
                    </h3>
                    {editingEntryId && <button type="button" onClick={() => setEditingEntryId(null)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors"><X className="w-5 h-5" /></button>}
                  </div>
                  <div className="space-y-4">
                    <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black outline-none focus:border-blue-900 transition-colors" required />
                    <div className="flex p-1 bg-slate-100 rounded-2xl">
                      <button type="button" onClick={() => setEntryMode('clock')} className={`flex-1 py-2 text-[10px] font-black rounded-xl transition-all ${entryMode === 'clock' ? 'bg-white shadow-sm text-blue-900' : 'text-slate-500'}`}>RELOJ</button>
                      <button type="button" onClick={() => setEntryMode('direct')} className={`flex-1 py-2 text-[10px] font-black rounded-xl transition-all ${entryMode === 'direct' ? 'bg-white shadow-sm text-blue-900' : 'text-slate-500'}`}>MANUAL</button>
                    </div>
                    {entryMode === 'clock' ? (
                      <div className="grid grid-cols-2 gap-3">
                        <input type="time" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-blue-900 outline-none" />
                        <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-blue-900 outline-none" />
                      </div>
                    ) : (
                      <input type="text" value={formData.hours} onChange={e => setFormData({...formData, hours: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl font-black focus:border-blue-900 outline-none" placeholder="hh:mm" />
                    )}
                    <div className="bg-white p-4 rounded-2xl border-2 border-slate-100 flex justify-between items-center">
                      <div><p className="text-[10px] font-black text-slate-400 uppercase mb-1">Comida</p><input type="text" value={formData.lunch} onChange={e => setFormData({...formData, lunch: e.target.value, isLunchManual: true})} className="w-16 bg-transparent text-lg font-black outline-none text-blue-900" /></div>
                      <button type="button" onClick={() => setFormData({...formData, isLunchManual: !formData.isLunchManual})} className={`text-[9px] font-black px-3 py-1.5 rounded-full border-2 transition-all ${formData.isLunchManual ? 'border-amber-200 text-amber-500' : 'border-slate-100 text-slate-400'}`}>{formData.isLunchManual ? 'MANUAL' : 'AUTO'}</button>
                    </div>
                    <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full border-2 border-slate-100 p-4 rounded-2xl text-xs h-24 focus:border-blue-900 outline-none resize-none" placeholder="Notas de la jornada..." />
                    <button type="submit" className={`w-full py-4 rounded-2xl text-white font-black shadow-xl transition-all active:scale-[0.98] ${editingEntryId ? 'bg-amber-500 hover:bg-amber-600 shadow-amber-100' : 'bg-blue-900 hover:bg-blue-950 shadow-blue-200'}`}>
                      {editingEntryId ? 'Guardar Cambios' : 'Registrar Jornada'}
                    </button>
                  </div>
                </form>
              </div>

              <div className="lg:col-span-2 space-y-4">
                <div className="flex justify-between items-center px-4 mb-2">
                  <h3 className="font-black text-slate-800 text-lg">Historial de Jornadas</h3>
                </div>
                {workerEntries.length === 0 && <div className="text-center py-20 bg-white border-2 border-dashed rounded-[2.5rem] text-slate-300 font-bold italic shadow-sm">No hay registros para este trabajador.</div>}
                {workerEntries.map(entry => {
                  const calc = calculateDay(entry.hoursBrutas, entry.lunchDiscount);
                  return (
                    <div key={entry.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <p className="font-black text-slate-800 text-lg capitalize">{new Date(entry.date).toLocaleDateString('es-ES', {weekday:'long', day:'numeric', month:'long'})}</p>
                          <p className="text-[9px] font-black text-slate-300 tracking-tighter uppercase mt-0.5 font-mono">ID: {entry.id}</p>
                        </div>
                        <div className="flex gap-2">
                          <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handleEditEntry(entry);
                            }} 
                            className="p-3 text-amber-500 hover:bg-amber-50 rounded-xl transition-all active:scale-90 relative z-10 cursor-pointer"
                            title="Editar"
                            aria-label="Editar registro"
                          >
                            <Edit2 className="w-5 h-5 pointer-events-none" />
                          </button>
                          <button 
                            type="button"
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              handleDeleteEntry(entry.id);
                            }} 
                            className="p-3 text-rose-500 hover:bg-rose-100 rounded-xl transition-all active:scale-90 relative z-10 cursor-pointer"
                            title="Eliminar registro"
                            aria-label="Eliminar registro"
                          >
                            <Trash2 className="w-5 h-5 pointer-events-none" />
                          </button>
                        </div>
                      </div>
                      <div className="grid grid-cols-4 gap-4 text-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Neta</p><p className="font-black text-blue-900 text-sm">{formatMinutes(calc.netas)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Extra</p><p className="font-black text-emerald-600 text-sm">+{formatMinutes(calc.extra)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Déficit</p><p className="font-black text-rose-500 text-sm">-{formatMinutes(calc.deficit)}</p></div>
                        <div><p className="text-[8px] font-black text-slate-400 uppercase mb-1">Bruta</p><p className="font-bold text-slate-400 text-sm">{formatMinutes(entry.hoursBrutas)}</p></div>
                      </div>
                      {entry.notes && <div className="mt-4 text-[11px] text-slate-500 italic flex gap-2 bg-slate-50 p-3 rounded-xl border border-slate-100"><FileText className="w-4 h-4 text-slate-300" /> {entry.notes}</div>}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {activeTab === 'balances' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleSaveCompensation} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                  <h3 className="font-black flex items-center gap-2 text-lg"><ArrowRightLeft className="w-5 h-5 text-blue-900" /> Compensar Bolsa</h3>
                  <div className="space-y-4">
                    <select value={compForm.type} onChange={e => setCompForm({...compForm, type: e.target.value as any})} className="w-full border-2 p-4 rounded-2xl font-black text-sm outline-none focus:border-blue-900">
                      <option value="PAYMENT">💰 Pago en Nómina</option>
                      <option value="REST_HOURS">🏖️ Descanso (Horas)</option>
                      <option value="FREE_DAY">📅 Día Libre Completo</option>
                    </select>
                    <input type="text" value={compForm.minutes} onChange={e => setCompForm({...compForm, minutes: e.target.value})} className="w-full border-2 p-4 rounded-2xl font-black focus:border-blue-900 outline-none" placeholder="hh:mm" />
                    <textarea value={compForm.notes} onChange={e => setCompForm({...compForm, notes: e.target.value})} className="w-full border-2 p-4 rounded-2xl text-xs h-24 focus:border-blue-900 outline-none resize-none" placeholder="Anotación..." />
                    <button type="submit" className="w-full py-4 bg-slate-800 text-white font-black rounded-2xl shadow-xl hover:bg-slate-900 transition-all active:scale-[0.98]">Aplicar Descuento</button>
                  </div>
                </form>
              </div>
              <div className="lg:col-span-2 bg-white rounded-[2.5rem] border shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Fecha</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cantidad</th>
                      <th className="px-8 py-5 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Acción</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {workerCompensations.map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(c.date).toLocaleDateString()}</td>
                        <td className="px-8 py-5"><span className="px-3 py-1 bg-blue-50 text-blue-900 rounded-lg text-[10px] font-black uppercase tracking-tight">{c.type}</span></td>
                        <td className="px-8 py-5 text-right font-black text-slate-800">{formatMinutes(c.minutes)}</td>
                        <td className="px-8 py-5 text-right">
                          <button onClick={() => handleDeleteComp(c.id)} className="text-rose-500 hover:bg-rose-50 p-3 rounded-xl transition-all active:scale-90">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {workerCompensations.length === 0 && <tr><td colSpan={4} className="py-20 text-center text-slate-300 italic font-medium">No hay compensaciones registradas.</td></tr>}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'workers' && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <form onSubmit={handleAddWorker} className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-5">
                  <h3 className="font-black text-slate-800 flex items-center gap-2 text-lg"><UserPlus className="w-5 h-5 text-blue-900" /> Nuevo Trabajador</h3>
                  <input type="text" value={newWorkerName} onChange={e => setNewWorkerName(e.target.value)} className="w-full border-2 p-4 rounded-2xl font-black outline-none focus:border-blue-900" placeholder="Nombre completo..." required />
                  <button type="submit" className="w-full py-4 bg-blue-900 text-white font-black rounded-2xl shadow-xl hover:bg-blue-950 transition-all active:scale-[0.98]">Añadir Perfil</button>
                </form>
              </div>
              <div className="lg:col-span-2 space-y-4">
                {workers.map(w => (
                  <div key={w.id} className={`flex items-center justify-between p-6 bg-white rounded-[2rem] border-2 transition-all ${selectedWorkerId === w.id ? 'border-blue-900 shadow-lg shadow-blue-100 ring-4 ring-blue-50' : 'border-slate-100 shadow-sm'}`}>
                    <div className="flex items-center gap-4">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${selectedWorkerId === w.id ? 'bg-blue-900 text-white' : 'bg-slate-100 text-slate-400'}`}>{w.name.charAt(0)}</div>
                      <div>
                        <p className="font-black text-slate-800 text-lg">{w.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest font-mono">ID: {w.id}</p>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedWorkerId(w.id)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${selectedWorkerId === w.id ? 'bg-blue-50 text-blue-900' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>
                        {selectedWorkerId === w.id ? 'ACTIVO' : 'SELECCIONAR'}
                      </button>
                      <button onClick={() => handleDeleteWorker(w.id)} className="p-3.5 text-rose-500 hover:bg-rose-50 rounded-xl transition-all active:scale-90"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="bg-white rounded-[2.5rem] border p-10 shadow-sm space-y-6">
              <h3 className="font-black text-xl text-slate-800 pb-4 border-b flex items-center gap-2 text-blue-900"><History className="w-6 h-6" /> Auditoría de Cambios</h3>
              <div className="space-y-4">
                {workerEntries.flatMap(e => (e.logs || []).map(l => ({...l, date: e.date}))).sort((a,b) => b.timestamp - a.timestamp).map(log => (
                  <div key={log.id} className="p-5 bg-slate-50 border border-slate-100 rounded-3xl flex gap-5 items-start transition-all hover:bg-slate-100/50">
                    <div className="bg-white p-3 rounded-xl border text-slate-300 shadow-sm"><History className="w-5 h-5" /></div>
                    <div className="flex-1 text-xs">
                      <div className="flex justify-between items-center mb-2">
                        <p className="font-black text-blue-900 uppercase tracking-tight text-[11px]">Jornada: {log.date}</p>
                        <p className="text-[10px] text-slate-400 font-bold">{new Date(log.timestamp).toLocaleString()}</p>
                      </div>
                      <p className="font-medium text-slate-600 leading-relaxed text-[13px]">
                        Campo <span className="text-slate-900 font-black">"{log.field}"</span> modificado. 
                        Valor anterior: <span className="text-slate-400 line-through">"{log.oldValue}"</span> → Nuevo valor: <span className="text-slate-900 font-black">"{log.newValue}"</span>.
                      </p>
                    </div>
                  </div>
                ))}
                {workerEntries.length === 0 && <div className="text-center py-20 text-slate-300 italic font-medium">Sin registros de auditoría para este perfil.</div>}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Menú Móvil */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-100 flex justify-around p-4 md:hidden z-50 shadow-2xl">
        {[
          {id:'daily', icon: Calendar, label: 'Jornada'}, 
          {id:'balances', icon: ArrowRightLeft, label: 'Bolsa'}, 
          {id:'workers', icon: Users, label: 'Equipo'}, 
          {id:'logs', icon: History, label: 'Logs'}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1.5 px-5 py-2 rounded-2xl transition-all ${activeTab === t.id ? 'text-blue-900 bg-blue-50 shadow-inner' : 'text-slate-400'}`}>
            <t.icon className="w-5 h-5" />
            <span className="text-[8px] font-black uppercase tracking-tighter">{t.label}</span>
          </button>
        ))}
      </nav>

      {/* Modal de Confirmación */}
      {deleteConfirmation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-[2rem] p-8 max-w-sm w-full shadow-2xl border-2 border-white scale-100 animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-rose-50 rounded-full flex items-center justify-center mb-6 mx-auto border-4 border-rose-100">
              <Trash2 className="w-8 h-8 text-rose-500" />
            </div>
            <h3 className="text-xl font-black text-slate-800 text-center mb-3 leading-tight">
              {deleteConfirmation.title}
            </h3>
            <p className="text-slate-500 text-center text-xs font-medium leading-relaxed mb-8 px-2">
              {deleteConfirmation.message}
            </p>
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setDeleteConfirmation(null)}
                className="py-4 px-4 rounded-2xl font-black text-xs uppercase tracking-wider text-slate-500 hover:bg-slate-50 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={executeDelete}
                className="py-4 px-4 rounded-2xl font-black text-xs uppercase tracking-wider text-white bg-rose-500 hover:bg-rose-600 shadow-xl shadow-rose-200 transition-all active:scale-95"
              >
                Sí, Eliminar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

export interface TimeEntry {
  id: string;
  workerId: string;
  date: string;
  hoursBrutas: number; // minutes
  lunchDiscount: number; // minutes
  isLunchManual: boolean;
  isFreeDay?: boolean; // Nueva propiedad
  notes?: string;
  logs: AuditLog[];
}

export interface CompensationEntry {
  id: string;
  workerId: string;
  date: string;
  type: 'PAYMENT' | 'REST_HOURS' | 'FREE_DAY';
  minutes: number;
  notes?: string;
}

export interface AuditLog {
  id: string;
  timestamp: number;
  field: string;
  oldValue: string;
  newValue: string;
  user: string;
  reason?: string;
}

export interface Worker {
  id: string;
  name: string;
}

export interface DailyCalculation {
  brutas: number;
  lunch: number;
  netas: number;
  ordinarias: number;
  extra: number;
  deficit: number;
  explanation: string;
}

export const parseHHMM = (hhmm: string): number => {
  const [h, m] = hhmm.split(':').map(Number);
  return (h || 0) * 60 + (m || 0);
};

export const formatMinutes = (minutes: number): string => {
  const isNegative = minutes < 0;
  const absMins = Math.abs(minutes);
  const h = Math.floor(absMins / 60);
  const m = absMins % 60;
  return `${isNegative ? '-' : ''}${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

export const calculateDay = (brutas: number, lunch: number, isFreeDay: boolean = false): any => {
  if (isFreeDay) {
    return {
      brutas: 0,
      lunch: 0,
      netas: 0,
      ordinarias: 0,
      extra: 0,
      deficit: 0,
      explanation: 'Día marcado como libre / no laborable (sin impacto en balance).'
    };
  }

  const netas = Math.max(0, brutas - lunch);
  const ordinarias = Math.min(480, netas); // 8h = 480m
  const extra = Math.max(0, netas - 480);
  const deficit = Math.max(0, 480 - netas);

  const explanation = `${formatMinutes(netas)} netas → ${formatMinutes(ordinarias)} ordinarias + ${formatMinutes(extra)} extra; comida ${formatMinutes(lunch)} aplicada.`;

  return { brutas, lunch, netas, ordinarias, extra, deficit, explanation };
};

import React, { useState, useMemo, useEffect } from 'react';
import { TimeEntry, CompensationEntry, Worker } from './types';
import { formatMinutes, parseHHMM, calculateDay } from './utils';
import { 
  Users, 
  Calendar, 
  Clock, 
  Plus, 
  History, 
  FileText, 
  ArrowRightLeft,
  UserPlus,
  Trash2,
  User,
  Edit2,
  X,
  AlertTriangle,
  Coffee,
  Briefcase
} from 'lucide-react';

const WORKDAY_MINUTES = 480; // 8h

const generateId = () => {
  return `ID-${Math.random().toString(36).substr(2, 9)}-${Date.now()}`;
};

const App: React.FC = () => {
  // Inicialización de estados desde localStorage
  const [workers, setWorkers] = useState<Worker[]>(() => {
    const saved = localStorage.getItem('tw_workers');
    return saved ? JSON.parse(saved) : [{ id: 'W-INITIAL', name: 'Trabajador Principal' }];
  });

  const [entries, setEntries] = useState<TimeEntry[]>(() => {
    const saved = localStorage.getItem('tw_entries');
    return saved ? JSON.parse(saved) : [];
  });

  const [compensations, setCompensations] = useState<CompensationEntry[]>(() => {
    const saved = localStorage.getItem('tw_compensations');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedWorkerId, setSelectedWorkerId] = useState<string>(() => {
    return localStorage.getItem('tw_last_worker') || (workers[0]?.id || 'W-INITIAL');
  });

  const [activeTab, setActiveTab] = useState<'daily' | 'balances' | 'workers' | 'logs'>('daily');

  // Estado para el modal de confirmación
  const [deleteConfirmation, setDeleteConfirmation] = useState<{
    id: string;
    type: 'ENTRY' | 'COMPENSATION' | 'WORKER';
    title: string;
    message: string;
  } | null>(null);

  // Sincronización automática de cambios de estado a localStorage
  useEffect(() => { localStorage.setItem('tw_workers', JSON.stringify(workers)); }, [workers]);
  useEffect(() => { localStorage.setItem('tw_entries', JSON.stringify(entries)); }, [entries]);
  useEffect(() => { localStorage.setItem('tw_compensations', JSON.stringify(compensations)); }, [compensations]);
  useEffect(() => { localStorage.setItem('tw_last_worker', selectedWorkerId); }, [selectedWorkerId]);

  const [entryMode, setEntryMode] = useState<'clock' | 'direct'>('clock');
  const [editingEntryId, setEditingEntryId] = useState<string | null>(null);

  // Form Data
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '08:00',
    endTime: '17:00',
    hours: '08:00',
    lunch: '01:00',
    isLunchManual: false,
    isFreeDay: false, // Nueva bandera
    notes: ''
  });

  const [compForm, setCompForm] = useState({
    type: 'PAYMENT' as CompensationEntry['type'],
    minutes: '01:00',
    notes: ''
  });

  const [newWorkerName, setNewWorkerName] = useState('');

  const workerEntries = useMemo(() => 
    entries.filter(e => String(e.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [entries, selectedWorkerId]);

  const workerCompensations = useMemo(() =>
    compensations.filter(c => String(c.workerId) === String(selectedWorkerId)).sort((a,b) => b.date.localeCompare(a.date)),
  [compensations, selectedWorkerId]);

  const totals = useMemo(() => {
    let extra = 0, deficit = 0, paid = 0, rested = 0, days = 0;
    workerEntries.forEach(e => {
      // Pasamos e.isFreeDay al cálculo para que no sume déficit si es día libre
      const c = calculateDay(e.hoursBrutas, e.lunchDiscount, e.isFreeDay);
      extra += c.extra; deficit += c.deficit;
    });
    workerCompensations.forEach(c => {
      if (c.type === 'PAYMENT') paid += c.minutes;
      else { rested += c.minutes; if(c.type === 'FREE_DAY') days++; }
    });
    return { pending: extra - paid - rested, deficit, paid, rested, days };
  }, [workerEntries, workerCompensations]);

  // --- SOLICITUDES DE BORRADO (ABREN MODAL) ---
  const handleDeleteEntry = (id: string) => {
    setDeleteConfirmation({
      id,
      type: 'ENTRY',
      title: '¿Eliminar Jornada?',
      message: 'Esta acción eliminará el registro permanentemente.'
    });
  };

  const handleDeleteComp = (id: string) => {
    setDeleteConfirmation({
      id,
      type: 'COMPENSATION',
      title: '¿Eliminar Compensación?',
      message: 'Se eliminará este registro de la bolsa de horas.'
    });
  };

  const handleDeleteWorker = (id: string) => {
    if (workers.length <= 1) {
      alert("Debe haber al menos un trabajador en el sistema.");
      return;
    }
    setDeleteConfirmation({
      id,
      type: 'WORKER',
      title: '¿Eliminar Trabajador?',
      message: '¡Atención! Se borrarán TODAS las jornadas y compensaciones asociadas a este perfil.'
    });
  };

  // --- EJECUCIÓN DE BORRADO ---
  const executeDelete = () => {
    if (!deleteConfirmation) return;
    const { id, type } = deleteConfirmation;

    if (type === 'ENTRY') {
      setEntries(prev => prev.filter(e => e.id !== id));
      if (editingEntryId === id) {
        setEditingEntryId(null);
        setFormData({
          date: new Date().toISOString().split('T')[0],
          startTime: '08:00', endTime: '17:00', hours: '08:00',
          lunch: '01:00', isLunchManual: false, isFreeDay: false, notes: ''
        });
      }
    } else if (type === 'COMPENSATION') {
      setCompensations(prev => prev.filter(c => c.id !== id));
    } else if (type === 'WORKER') {
      setWorkers(prev => {
        const newWorkers = prev.filter(w => w.id !== id);
        if (selectedWorkerId === id) setSelectedWorkerId(newWorkers[0].id);
        return newWorkers;
      });
      setEntries(prev => prev.filter(e => e.workerId !== id));
      setCompensations(prev => prev.filter(c => c.workerId !== id));
    }

    setDeleteConfirmation(null);
  };

  // --- HANDLERS CREAR/EDITAR ---
  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();

    // Si es día libre, las horas son 0. Si no, calculamos normal.
    let brutas = 0;
    let lunch = 0;

    if (!formData.isFreeDay) {
        brutas = entryMode === 'direct' ? parseHHMM(formData.hours) : 
        (() => {
            const s = parseHHMM(formData.startTime), f = parseHHMM(formData.endTime);
            return f >= s ? f - s : (1440 - s) + f;
        })();
        lunch = parseHHMM(formData.lunch);
        if (!formData.isLunchManual && brutas > WORKDAY_MINUTES) lunch = 60;
    }

    if (editingEntryId) {
      setEntries(current => {
        const updated = current.map(ent => 
          String(ent.id) === String(editingEntryId) 
            ? { 
                ...ent, 
                date: formData.date, 
                hoursBrutas: brutas, 
                lunchDiscount: lunch, 
                isFreeDay: formData.isFreeDay,
                notes: formData.notes 
              }
            : ent
        );
        return updated;
      });
      setEditingEntryId(null);
    } else {
      const newEntry: TimeEntry = {
        id: generateId(),
        workerId: selectedWorkerId,
        date: formData.date,
        hoursBrutas: brutas,
        lunchDiscount: lunch,
        isLunchManual: formData.isLunchManual,
        isFreeDay: formData.isFreeDay,
        notes: formData.notes,
        logs: []
      };
      setEntries(current => [newEntry, ...current]);
    }
    // Resetear formulario manteniendo la fecha actual o siguiente podría ser útil, pero reseteamos notas
    setFormData(prev => ({ ...prev, notes: '' }));
  };

  const handleEditEntry = (entry: TimeEntry) => {
    setEditingEntryId(entry.id);
    setFormData({
      date: entry.date,
      startTime: '08:00', endTime: '17:00',
      hours: formatMinutes(entry.hoursBrutas),
      lunch: formatMinutes(entry.lunchDiscount),
      isLunchManual: entry.isLunchManual,
      isFreeDay: entry.isFreeDay || false,
      notes: entry.notes || ''
    });
    setEntryMode('direct'); // Al editar, por defecto mostrar direct o mantener lógica anterior
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSaveCompensation = (e: React.FormEvent) => {
    e.preventDefault();
    const mins = parseHHMM(compForm.minutes);
    if (mins <= 0) return alert("Cantidad no válida.");
    const newComp: CompensationEntry = {
      id: generateId(),
      workerId: selectedWorkerId,
      date: new Date().toISOString().split('T')[0],
      type: compForm.type,
      minutes: mins,
      notes: compForm.notes
    };
    setCompensations(current => [newComp, ...current]);
    setCompForm({ ...compForm, minutes: '01:00', notes: '' });
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newWorkerName.trim()) return;
    const newWorker: Worker = { id: `W-${Date.now()}`, name: newWorkerName.trim() };
    setWorkers(current => [...current, newWorker]);
    setNewWorkerName('');
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-blue-900 p-2 rounded-xl shadow-lg shadow-blue-200"><Clock className="text-white w-6 h-6" /></div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">TimeGuard Pro</h1>
            <p className="text-[9px] text-emerald-600 font-bold uppercase flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span> Sistema de Registro Seguro
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
          <User className="text-slate-400 w-4 h-4 ml-1" />
          <select value={selectedWorkerId} onChange={(e) => setSelectedWorkerId(e.target.value)} className="bg-transparent border-none font-bold text-slate-700 outline-none min-w-[160px] text-sm cursor-pointer">
            {workers.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
          </select>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8 space-y-8">
        {/* Dashboard */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
