              </button>
              <button 
                onClick={executeDelete}
                className="py-4 px-4 rounded-2xl font-black text-xs uppercase tracking-wider text-white bg-rose-500 hover:bg-rose-600 shadow-xl shadow-rose-200 transition-all active:scale-95"
              >
                Sí, Eliminar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

export interface TimeEntry {
  id: string;
  workerId: string;
  date: string;
  hoursBrutas: number; // minutes
  lunchDiscount: number; // minutes
  isLunchManual: boolean;
  isFreeDay?: boolean; // Nueva propiedad
  notes?: string;
  logs: AuditLog[];
}

export interface CompensationEntry {
  id: string;
  workerId: string;
  date: string;
  type: 'PAYMENT' | 'REST_HOURS' | 'FREE_DAY';
  minutes: number;
  notes?: string;
}

export interface AuditLog {
  id: string;
  timestamp: number;
  field: string;
  oldValue: string;
  newValue: string;
  user: string;
  reason?: string;
}

export interface Worker {
  id: string;
  name: string;
  isActive?: boolean; // Controla si está dado de alta o baja
}

export interface DailyCalculation {
  brutas: number;
  lunch: number;
  netas: number;
  ordinarias: number;
  extra: number;
  deficit: number;
  explanation: string;
}

