                            title="Eliminar registro"
                          >
                            <Trash2 className="w-5 h-5 pointer-events-none" />
                          </button>
                        </div>
                      </div>

                      {entry.isFreeDay ? (
                          <div className="bg-slate-100 rounded-2xl p-4 flex items-center justify-center gap-2 border border-slate-200 border-dashed">
